import type { Drill } from "./types";

// Finance / mid drills, keyed by module slug — 25 per module.
// A finance manager / controller who business-partners with department heads:
// budget reviews, forecasts upward, audit coordination, spend decisions. Merged into course.ts.
export const FINANCE_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-fin-mid-01","level":"mid","profession":"finance","title":"The variance email that opens with methodology","scenario":"Marketing is $180K over budget for the quarter, driven by one unplanned agency contract. Your draft email to the marketing director opens with two paragraphs on how the variance report is calculated before the number appears.","task":"Write a 2-3 sentence email opening that leads with the overspend and its driver.","tips":["Sentence one: the number and the cause.","Methodology belongs in an appendix, if anywhere.","End the opening with what you need from them."],"focus":["structure","clarity"],"placeholder":"Marketing is $180K over budget this quarter, driven by the unplanned agency contract signed in May."},
    {"id":"lead-fin-mid-02","level":"mid","profession":"finance","title":"The re-forecast that buries the headline","scenario":"Your mid-year re-forecast shows full-year revenue coming in 4% below plan. Your memo to the CFO's office currently opens with a description of the forecast process and the departments you consulted.","task":"Rewrite the memo opening so the 4% miss is the first sentence.","tips":["The CFO's office reads sentence one and decides whether to keep reading.","Process detail proves rigor — but only after the conclusion.","Name the one or two drivers right behind the headline."],"focus":["structure","impact"],"placeholder":"The re-forecast shows full-year revenue 4% below plan, driven by"},
    {"id":"lead-fin-mid-03","level":"mid","profession":"finance","title":"The decline that eases in","scenario":"You're declining a $45K software request from the operations director because the department has no remaining discretionary budget this year. Your draft spends four sentences on how much you value the partnership before saying no.","task":"Write a 3-4 sentence reply that states the decision in sentence one.","tips":["Lead with the decision, not the cushioning.","One clear reason beats three soft ones.","Offer the path forward: what would change the answer."],"focus":["clarity","impact"]},
    {"id":"lead-fin-mid-04","level":"mid","profession":"finance","title":"The conditional approval","scenario":"You can approve the sales team's request for two new hires, but only if the start dates move to Q3 so the cost fits this year's budget. Your draft explains the budget math before revealing the approval.","task":"Write a 2-3 sentence reply that leads with the approval and its condition together.","tips":["'Yes, if' is one sentence — keep the approval and condition attached.","Don't let them read 'approved' and skim past the condition.","The math is support; put it after."],"focus":["clarity","precision"],"placeholder":"Approved, with one condition: both start dates move to Q3."},
    {"id":"lead-fin-mid-05","level":"mid","profession":"finance","title":"The close slipping a day","scenario":"Month-end close will finish Thursday instead of Wednesday because two departments submitted accruals late. The CFO's office is waiting on the numbers for a leadership meeting. Your draft opens with the story of the late submissions.","task":"Write a 2-sentence update that leads with the new date and what it affects.","tips":["First words: close lands Thursday.","Say immediately what downstream deadline it touches.","Cause comes last, in half a sentence."],"focus":["clarity","concision"],"placeholder":"Close will finish Thursday, one day late — the numbers will still be ready before Friday's leadership meeting."},
    {"id":"lead-fin-mid-06","level":"mid","profession":"finance","title":"The audit request lost in pleasantries","scenario":"The auditors need three signed vendor contracts from the procurement team by Friday, or the audit timeline slips. Your draft to the procurement lead spends a paragraph on audit season before naming the documents.","task":"Write an email opening that puts the ask and the Friday deadline in sentence one.","tips":["Name the documents, the deadline, and who needs them — first.","The consequence of missing Friday earns one sentence.","Warmth can live in the sign-off, not the opening."],"focus":["clarity","structure"]},
    {"id":"lead-fin-mid-07","level":"mid","profession":"finance","title":"Coaching the buried lede","scenario":"Your analyst drafted the monthly commentary for the CFO pack. The key point — cloud costs jumped 22% and will keep climbing — is in the final paragraph, after seven paragraphs of line-item detail.","task":"Write a 2-3 sentence note to the analyst explaining what to move and why.","tips":["Name the fix: headline first, detail after.","Explain the reader's behavior: executives read top-down and stop.","Keep the feedback about the draft, not the person."],"focus":["structure","clarity"]},
    {"id":"lead-fin-mid-08","level":"mid","profession":"finance","title":"The cash alert","scenario":"Customer collections have slowed and month-end cash will land roughly $600K below plan. Nothing is broken yet, but the CFO's office should know today. Your instinct is to open with reassurance before the number.","task":"Write a 2-3 sentence message that leads with the cash position and its cause.","tips":["Lead with the number and the direction — that is the news.","Reassurance is credible only after the facts.","Close with the action you're taking or the decision you need."],"focus":["clarity","impact"],"placeholder":"Month-end cash will land about $600K below plan — collections slowed in the last two weeks."},
    {"id":"lead-fin-mid-09","level":"mid","profession":"finance","title":"Opening the budget review","scenario":"You're opening the quarterly budget review with the engineering director. The headline: the department is trending 12% over its full-year budget and needs to choose between slowing hiring and cutting contractor spend. You have 30 minutes.","task":"Write the first two sentences you would say to open the meeting.","tips":["Open with the trend and the decision the meeting exists to make.","Don't warm up with a tour of the report.","Frame the choice so the next 28 minutes have a job."],"focus":["structure","impact"],"placeholder":"You're trending 12% over budget for the year, and today I want to leave with a decision:"},
    {"id":"lead-fin-mid-10","level":"mid","profession":"finance","title":"'Can we afford it?' answered last","scenario":"The HR director asked whether the department can afford an off-site in September. The answer is yes — if they defer the planned training vendor to next quarter. Your draft walks through the whole budget before answering.","task":"Write a reply of 2-3 sentences that answers the question in the first clause.","tips":["Give the verdict first: yes, with a trade-off.","Name the trade-off in the same breath as the yes.","The supporting numbers can follow or be attached."],"focus":["clarity","concision"]},
    {"id":"lead-fin-mid-11","level":"mid","profession":"finance","title":"The auto-renewal countdown","scenario":"A data-services contract auto-renews in 30 days at an 18% price increase unless someone cancels or renegotiates. The IT director owns the relationship but doesn't know the clock is running. Your draft opens with contract history.","task":"Write a 2-sentence heads-up that leads with the deadline and the decision needed.","tips":["The 30-day clock is the point — put it first.","Name the decision owner explicitly.","History matters only if it changes the decision."],"focus":["clarity","impact"],"placeholder":"The DataServe contract auto-renews in 30 days at +18% — we need your renew-or-renegotiate call by the 15th."},
    {"id":"lead-fin-mid-12","level":"mid","profession":"finance","title":"The good news buried under caveats","scenario":"Operations finished the quarter $95K under budget, enough to fund the warehouse-scanning pilot they've wanted all year. Your draft to the ops director opens with three caveats about one-time timing effects before sharing the number.","task":"Write a 2-3 sentence message that leads with the good news, then the one caveat that matters.","tips":["Good news deserves the headline too.","Pick the single caveat that changes what they can do; drop the rest.","Connect the number to the decision it unlocks."],"focus":["structure","clarity"]},
    {"id":"lead-fin-mid-13","level":"mid","profession":"finance","title":"The exception that needs a ruling","scenario":"A regional manager booked business-class flights that exceed policy by $3,200, with a plausible medical reason. You can't approve it yourself; the CFO's office must rule. Your draft narrates the whole trip before stating what you need.","task":"Write a 2-3 sentence message to the CFO's office that leads with the decision you need and by when.","tips":["First sentence: the ruling you need and the deadline.","Compress the situation to one sentence of context.","State your own recommendation — don't just forward the problem."],"focus":["clarity","structure"],"placeholder":"I need a policy-exception ruling by Thursday: a $3,200 over-policy airfare with a documented medical reason."},
    {"id":"lead-fin-mid-14","level":"mid","profession":"finance","title":"Chasing the board-pack inputs","scenario":"Board materials are due to the CFO's office Monday, and three department heads still haven't submitted their quarterly numbers. Your reminder draft opens with an apology for the extra email.","task":"Write a 2-sentence chase that leads with the deadline and exactly what's missing.","tips":["Name the artifact, the owner, and the date in sentence one.","Cut the apology — a clear ask is not an imposition.","Say what happens to their section if the deadline slips."],"focus":["clarity","concision"]},
    {"id":"lead-fin-mid-15","level":"mid","profession":"finance","title":"The duplicate payment discovery","scenario":"Your team found that a vendor was paid the same $28K invoice twice. Recovery is already underway and the vendor has acknowledged it. Your update to your controller starts with how the reconciliation process caught it.","task":"Write a 2-3 sentence update that leads with what happened and the current status.","tips":["Headline: the error, the amount, and 'recovery underway.'","The process story is supporting detail.","Say when you expect the money back."],"focus":["clarity","precision"],"placeholder":"We double-paid a $28K vendor invoice; the vendor has confirmed and refund is expected within 10 days."},
    {"id":"lead-fin-mid-16","level":"mid","profession":"finance","title":"Explaining your own miss","scenario":"Your Q2 forecast missed by $340K, and nearly all of it traces to one enterprise deal that slipped to Q3. Your note to your VP starts by defending the forecast process in general terms.","task":"Write a 2-3 sentence note that leads with the miss and its single driver.","tips":["Own the number in sentence one.","One driver explained clearly beats five explained vaguely.","End with what you changed so it doesn't repeat."],"focus":["clarity","impact"]},
    {"id":"lead-fin-mid-17","level":"mid","profession":"finance","title":"Hold or release the contingency","scenario":"There's $250K of unallocated contingency in this year's budget. Two departments want it; you think it should be held until Q4 given forecast risk. You're writing to the CFO's office for a decision, and your draft opens with the two departments' cases.","task":"Write an opening of 2-3 sentences that leads with the decision needed and your recommendation.","tips":["Frame it as a decision request, not a situation report.","State your recommendation before the competing cases.","Give the date by which the decision matters."],"focus":["structure","impact"],"placeholder":"Decision needed by month-end: hold or release the $250K contingency. I recommend holding it until Q4 because"},
    {"id":"lead-fin-mid-18","level":"mid","profession":"finance","title":"The accrual deadline reminder","scenario":"Quarter-end accrual submissions are due from all department heads by the 25th, and last quarter three of them were late, delaying close by two days. Your reminder draft explains what accruals are for two paragraphs.","task":"Write a 2-sentence reminder that leads with the deadline and the consequence of missing it.","tips":["Deadline first, consequence second — done.","They don't need accounting theory; they need the date.","Make the submission mechanics one link, not one paragraph."],"focus":["concision","clarity"]},
    {"id":"lead-fin-mid-19","level":"mid","profession":"finance","title":"'Why is my budget red?'","scenario":"A department head pings you on Slack: 'My dashboard shows red — why?' The answer is one thing: an annual software license hit in month one instead of spreading across the year. Your instinct is to explain how the dashboard colors work.","task":"Write a 1-2 sentence Slack reply that gives the driver first.","tips":["Answer the actual question in the first sentence.","'It looks worse than it is' needs the reason attached.","Offer the fix or the outlook in the second sentence."],"focus":["clarity","concision"],"placeholder":"One driver: the annual Salesforce license hit January in full instead of spreading across 12 months."},
    {"id":"lead-fin-mid-20","level":"mid","profession":"finance","title":"The purchase-order bypass","scenario":"The facilities team has made four purchases this quarter without purchase orders, which breaks the approval controls the auditors tested last year. You need to escalate to the facilities director. Your draft buries the pattern under the four individual stories.","task":"Write a 2-3 sentence escalation that names the pattern first, then the stakes.","tips":["Lead with the pattern: four bypasses this quarter.","Stakes in sentence two: this is an audit finding waiting to happen.","Ask for one specific change, not general carefulness."],"focus":["clarity","impact"]},
    {"id":"lead-fin-mid-21","level":"mid","profession":"finance","title":"The capex recommendation","scenario":"You reviewed the $380K warehouse-equipment request and recommend approving it: it pays back in under two years and the current equipment's maintenance costs are climbing. Your summary for the approval committee opens with the request's history.","task":"Write a 2-3 sentence summary that leads with your recommendation and the payback.","tips":["Recommendation and headline number in sentence one.","The committee wants your verdict, then your reasons.","Two supporting reasons, then stop."],"focus":["structure","precision"],"placeholder":"I recommend approving the $380K warehouse equipment request: it pays back in 22 months and"},
    {"id":"lead-fin-mid-22","level":"mid","profession":"finance","title":"The template nobody returned","scenario":"You sent budget-planning templates to eight department heads two weeks ago; five haven't returned them and planning season starts Monday. Your follow-up draft opens with 'Just circling back on my earlier email.'","task":"Write a follow-up of 2 sentences that leads with what you need and the real deadline.","tips":["Cut 'circling back' — lead with the ask and date.","Name the consequence: departments that miss Monday get last year's numbers as their starting point.","Address it to the five, not a vague 'all.'"],"focus":["clarity","impact"]},
    {"id":"lead-fin-mid-23","level":"mid","profession":"finance","title":"Reporting delayed by the outage","scenario":"The finance system was down for six hours today, so the weekly spend reports department heads expect Friday morning will now arrive Monday. Your announcement draft opens with a detailed outage timeline.","task":"Write a 2-sentence notice that leads with the new delivery date.","tips":["Readers want one thing: when do I get my report?","The outage gets a half-sentence of cause, no timeline.","Say whether any action is needed from them (none, probably)."],"focus":["concision","clarity"],"placeholder":"Friday's spend reports will arrive Monday morning instead —"},
    {"id":"lead-fin-mid-24","level":"mid","profession":"finance","title":"The two-lever decision","scenario":"To close a $200K gap in the department's budget, the sales director must either cut the travel budget by a third or delay two planned hires by a quarter. You need their choice by Friday. Your draft explains the gap's origins at length first.","task":"Write an email opening that leads with the decision, the two options, and the Friday deadline.","tips":["Decision and deadline in sentence one.","Present the two levers cleanly — one line each.","Origins of the gap are background; link or footnote them."],"focus":["structure","clarity"]},
    {"id":"lead-fin-mid-25","level":"mid","profession":"finance","title":"The hallway status check","scenario":"Your controller catches you in the corridor: 'Thirty seconds — where are we on the re-forecast?' The true status: numbers are in from all but one department, the draft goes to the CFO's office Thursday, and the one open risk is sales pipeline data.","task":"Write the 2-sentence spoken answer that leads with the status headline.","tips":["Headline: on track for Thursday.","One risk, named specifically.","Practice saying it aloud — it should take ten seconds."],"focus":["concision","structure"],"placeholder":"On track — draft to the CFO's office Thursday. One open risk:"}
  ],
  "start-with-the-audience": [
    {"id":"audience-fin-mid-01","level":"mid","profession":"finance","title":"Accruals for a sales director","scenario":"The sales director is upset that a $60K event expense shows in this month's numbers when the invoice hasn't even arrived. The answer is an accrual, but 'we accrued the estimated cost in the period the event occurred' will not land.","task":"Write a 2-3 sentence explanation in plain language a non-finance leader can accept.","tips":["Explain the why (costs count when the event happens, not when the bill arrives), not the term.","Connect it to their stake: their budget reflects reality sooner.","Say what happens when the real invoice comes in."],"focus":["audience","clarity"],"placeholder":"We recorded the event's cost in the month it happened, even though the invoice hasn't arrived yet —"},
    {"id":"audience-fin-mid-02","level":"mid","profession":"finance","title":"Timing, not overspend","scenario":"The engineering director's dashboard shows the team 30% over budget for the month, and he's alarmed. The truth: a quarterly cloud invoice landed this month, and the quarter as a whole is on plan. He doesn't think in monthly phasing.","task":"Write a 2-3 sentence reply that reframes the number in terms he cares about.","tips":["Answer the fear first: you're fine for the quarter.","Explain the lumpy invoice in one plain sentence.","Tell him which number to watch instead."],"focus":["audience","clarity"]},
    {"id":"audience-fin-mid-03","level":"mid","profession":"finance","title":"De-jargon the commentary","scenario":"Your variance commentary reads: 'Unfavorable opex variance driven by under-accrued professional fees and adverse FX on vendor contracts.' It's going to the operations leader, who runs warehouses, not spreadsheets.","task":"Rewrite the sentence so a non-finance operations leader understands it on first read.","tips":["Translate every finance term: unfavorable, opex, accrued, FX.","Name what actually happened in the world, not in the ledger.","Keep the quantified impact — plain language doesn't mean vague."],"focus":["audience","precision"],"placeholder":"Costs came in higher than planned for two reasons: consultant bills were larger than we'd estimated, and"},
    {"id":"audience-fin-mid-04","level":"mid","profession":"finance","title":"Altitude for the CFO's office","scenario":"You drafted a full page on the department-by-department drivers of the quarter's overspend for the CFO's chief of staff. She forwards summaries to the CFO, who has ninety seconds per topic. Your page is written at analyst altitude.","task":"Write the 3-sentence version pitched at CFO altitude.","tips":["Lead with the total and whether it threatens the full-year number.","Departments become one clause each, or disappear.","End with the decision or reassurance the CFO needs."],"focus":["audience","concision"]},
    {"id":"audience-fin-mid-05","level":"mid","profession":"finance","title":"Spreading the cost of the forklift","scenario":"The facilities manager wants to know why the $90K forklift he bought in March 'only shows $2,500 a month' in his numbers. The answer is that large equipment costs are spread over their useful life — but he has never heard of depreciation.","task":"Write a 2-3 sentence explanation without using the word 'depreciation' or any accounting term.","tips":["Use the logic, not the label: the cost is spread over the years the machine works.","Anchor to his experience: the machine serves him for six years, so does its cost.","Confirm the cash already left — only the reporting spreads it."],"focus":["audience","clarity"],"placeholder":"You paid the full $90K in March, but in your reports we spread that cost over the six years the forklift will be in service —"},
    {"id":"audience-fin-mid-06","level":"mid","profession":"finance","title":"Onboarding the new director","scenario":"A new department head starts Monday. She needs to know the budget rhythm — monthly reviews with you, quarterly re-forecasts, accruals by the 25th, spend requests above $10K need your sign-off — but she knows none of the history or acronyms.","task":"Write a 4-5 sentence welcome note that assumes zero context.","tips":["Spell out every process the first time; no internal shorthand.","Order it by what she'll hit first, not by what finance finds important.","Name the one deadline that bites hardest if missed."],"focus":["audience","structure"]},
    {"id":"audience-fin-mid-07","level":"mid","profession":"finance","title":"Why the auditors want payroll files","scenario":"The HR director is uneasy: auditors have requested a sample of payroll records and she reads it as an investigation of her team. It's a routine annual test that every audit includes. Your explanation needs to remove the alarm without dismissing her.","task":"Write a 3-sentence explanation that addresses her actual worry first.","tips":["Name the fear and answer it: this is routine, not targeted.","Explain what the auditors do with the sample in one plain sentence.","Tell her exactly what she needs to provide and by when."],"focus":["audience","clarity"]},
    {"id":"audience-fin-mid-08","level":"mid","profession":"finance","title":"The cost of hiring early","scenario":"A manager wants to move a planned October hire to June and doesn't see the problem — 'it's the same salary either way.' The issue: four extra months of cost this year, about $45K the department doesn't have. He thinks in headcount, not in-year cost.","task":"Write a 2-3 sentence explanation that translates the timing into his budget reality.","tips":["Convert the abstraction: earlier start = more months on this year's budget.","Give the number: roughly $45K more this year.","Offer the honest option: find $45K elsewhere, or hold to October."],"focus":["audience","precision"],"placeholder":"Same salary, but a June start puts four extra months of cost — about $45K — into this year's budget."},
    {"id":"audience-fin-mid-09","level":"mid","profession":"finance","title":"One email, two audiences","scenario":"You drafted one email announcing the Q3 re-forecast process, addressed to both the CFO's office and all department heads. The CFO's office needs the timeline and risk summary; department heads need instructions and deadlines. It serves neither.","task":"Write the 2-3 sentence department-head version, then the 1-2 sentence CFO's-office version.","tips":["Pick one primary audience per message — split rather than blend.","Department heads: what to do, by when, in what format.","CFO's office: when they see the output and what might move."],"focus":["audience","structure"]},
    {"id":"audience-fin-mid-10","level":"mid","profession":"finance","title":"'What's our run rate?'","scenario":"The marketing lead asks what her team's 'run rate' is — she's heard the term in a leadership meeting and is embarrassed to ask what it means. You could answer with the number alone, but she needs the concept to use it.","task":"Write a 2-3 sentence reply that gives her the number and the plain meaning together.","tips":["Define it in her terms: what you spend in a typical month, projected forward.","Give her number and what it implies for year-end.","Never make the asker feel the question was dumb."],"focus":["audience","clarity"],"placeholder":"Your run rate is about $210K a month — that's your current spending pace, and at that pace you'd end the year"},
    {"id":"audience-fin-mid-11","level":"mid","profession":"finance","title":"The model change nobody asked about","scenario":"You've switched the forecast from simple trend extrapolation to a driver-based model using headcount and sales pipeline. Department heads will notice their numbers moved and suspect games. They don't care about modeling; they care about whether their targets changed.","task":"Write a 3-4 sentence announcement framed around what changes for them.","tips":["Lead with their stake: numbers may shift, targets have not.","Describe the change by its benefit: forecasts now move when your drivers move.","One sentence on what you need from them, if anything."],"focus":["audience","clarity"]},
    {"id":"audience-fin-mid-12","level":"mid","profession":"finance","title":"A shift is not a cut","scenario":"A team lead heard her project budget was 'reduced this quarter' and is telling people the project is being killed. In fact the total is unchanged — spend was rephased to match the revised delivery schedule. Panic is spreading faster than your spreadsheet.","task":"Write a 2-3 sentence message that corrects the story in her terms, not finance's.","tips":["Answer the fear first: the total budget is unchanged.","Explain rephasing as matching money to the new schedule.","Give the concrete numbers: what moved from when to when."],"focus":["audience","clarity"],"placeholder":"Your total project budget is unchanged — nothing was cut."},
    {"id":"audience-fin-mid-13","level":"mid","profession":"finance","title":"The table dump","scenario":"Your analyst prepared a business-review page for the customer-success director: a 40-row expense table with no commentary. The director's actual question is simple — can she afford the two contractors she wants in Q4? The table technically contains the answer.","task":"Write a 2-3 sentence note to the analyst on how to reframe the page for its reader.","tips":["Start from the reader's question, not the available data.","The answer goes on top; the table becomes backup.","Have the analyst write the one sentence the director will quote."],"focus":["audience","structure"]},
    {"id":"audience-fin-mid-14","level":"mid","profession":"finance","title":"Why month one always looks light","scenario":"The plant manager complains that his first month of each quarter always shows him 'way under budget' and then he gets told to slow spending by his boss, who reads the same report. The cause: quarterly maintenance contracts bill in month three. This keeps happening.","task":"Write a 2-3 sentence explanation he can forward to his boss verbatim.","tips":["Write it for the boss reading over his shoulder — that's the real audience.","Plain cause: quarterly bills land in month three, so months one and two look light.","Point to the quarter-level view as the number to manage on."],"focus":["audience","clarity"]},
    {"id":"audience-fin-mid-15","level":"mid","profession":"finance","title":"The allocation surprise","scenario":"The customer-support director's costs jumped $30K this month because IT allocations were rebalanced — support's growing headcount means it now carries a bigger share of shared IT costs. To her it looks like a bill for something she never bought.","task":"Write a 3-sentence explanation of the allocation change in her terms.","tips":["Explain the principle plainly: shared costs are split by how much each team uses.","Name what changed: her team grew, so her share grew.","Say what she can and cannot control about it — honestly."],"focus":["audience","clarity"],"placeholder":"The $30K is your team's share of company-wide IT costs — we split those by headcount, and your team grew."},
    {"id":"audience-fin-mid-16","level":"mid","profession":"finance","title":"One paragraph for the chief of staff","scenario":"The CEO's chief of staff asks where the cost-savings program stands. You have a 15-tab tracker. What she actually needs: is it on track, what's the number, and does the CEO need to do anything. She'll spend forty seconds on your reply.","task":"Write the one-paragraph (3-4 sentence) reply pitched exactly at her need.","tips":["Her three questions, in order: on track? number? action needed?","Tracker detail is available on request — say so in five words.","If nothing is needed from the CEO, say that explicitly; it's information."],"focus":["audience","concision"],"placeholder":"On track: $1.1M of the $1.5M target is locked in, and"},
    {"id":"audience-fin-mid-17","level":"mid","profession":"finance","title":"Delivering the finding without the finding-speak","scenario":"The audit flagged that the procurement team approved invoices without matching purchase orders. The formal finding language — 'control deficiency in the three-way match process' — will read as an accusation. The team needs to fix the behavior, not decode the jargon.","task":"Write a 3-sentence explanation of the finding for the procurement team in plain, blame-free terms.","tips":["Describe the gap as a process fact, not a personal failure.","Translate 'three-way match' into what to actually do differently.","End with the fix and who owns it."],"focus":["audience","clarity"]},
    {"id":"audience-fin-mid-18","level":"mid","profession":"finance","title":"Committed versus spent","scenario":"A project manager insists she has '$80K left' because that's what the spend report shows. But she's signed contracts for $65K of work not yet billed — she really has $15K of room. The distinction between spent and committed has never been explained to her.","task":"Write a 2-3 sentence explanation of committed vs. spent using her project's numbers.","tips":["Use her numbers, not definitions: $80K unspent, $65K promised, $15K truly free.","One plain metaphor-free explanation: signed contracts are spoken-for money.","Tell her which number to check before signing anything new."],"focus":["audience","precision"],"placeholder":"Your report shows $80K unspent, but $65K of that is already promised under signed contracts —"},
    {"id":"audience-fin-mid-19","level":"mid","profession":"finance","title":"Cash timing for the leadership team","scenario":"You're presenting the cash outlook to the leadership team. Your draft talks about 'working capital movements' and 'receivables aging.' What they can actually act on: two big customers pay 20+ days late, and leaning on them frees roughly $400K this quarter.","task":"Write the 2-3 sentences you'd say, framed around what leaders can do.","tips":["Lead with the actionable fact, not the balance-sheet vocabulary.","Name the lever and its size: chase two accounts, free ~$400K.","Assign the ask: whose relationships are these customers?"],"focus":["audience","impact"]},
    {"id":"audience-fin-mid-20","level":"mid","profession":"finance","title":"The miscoded expense","scenario":"An annoyed director emails: a $12K charge on her budget belongs to another team. She's right — it was coded to the wrong cost center — and it will be fixed in next month's numbers. Your reply needs to fix the relationship as well as the record.","task":"Write a 2-3 sentence reply that validates her, explains plainly, and gives the fix date.","tips":["Concede immediately: she's right, it's a coding error.","Explain without jargon: charged to the wrong team's budget by mistake.","Give the specific month the correction appears — vague fixes erode trust."],"focus":["audience","clarity"],"placeholder":"You're right — that $12K belongs to the logistics team and was coded to your budget by mistake."},
    {"id":"audience-fin-mid-21","level":"mid","profession":"finance","title":"Talking points two audiences up","scenario":"The CFO asked for talking points on department spending for the board meeting. Your natural draft explains what happened. But the board's questions are different: is spending under control, and does anything here change the year's guidance?","task":"Write 2-3 talking-point sentences aimed at what a board member would ask.","tips":["Write for the audience's audience: the board, not the CFO.","Answer the control question directly, with one number.","Flag guidance impact explicitly, even if the answer is 'none.'"],"focus":["audience","impact"]},
    {"id":"audience-fin-mid-22","level":"mid","profession":"finance","title":"Explaining the freeze exception path","scenario":"A hiring freeze is on, but critical roles can still be approved through an exception process: business case, your review, CFO sign-off, roughly two weeks. Managers currently believe the freeze is absolute and are quietly giving up on essential backfills.","task":"Write a 3-4 sentence explanation of the exception path for managers.","tips":["Correct the misunderstanding first: critical roles can still move.","Lay out the path in steps as the manager experiences them.","Be honest about the bar and the timeline — false hope costs more."],"focus":["audience","structure"]},
    {"id":"audience-fin-mid-23","level":"mid","profession":"finance","title":"The acronym-proof memo","scenario":"Your budget memo to all department heads currently includes FX, COGS, opex, and YTD in the first paragraph. Half your readers run kitchens, warehouses, and support desks. Every acronym is a small door slammed in their face.","task":"Rewrite the paragraph's key sentence in words every reader owns.","tips":["Replace each acronym with its plain meaning or cut it.","'Year-to-date' costs nothing to spell out; do it.","Read it as a warehouse manager would — anything that snags, rewrite."],"focus":["audience","clarity"],"placeholder":"Through the end of June, spending across departments is 4% above plan, mostly because"},
    {"id":"audience-fin-mid-24","level":"mid","profession":"finance","title":"Forecast confidence in sales language","scenario":"The sales VP asks how confident you are in the revenue forecast. Your honest answer involves scenario weightings, but he thinks in pipeline: deals, stages, coverage. Translating into his frame will land better than your statistics.","task":"Write a 2-3 sentence answer expressed in pipeline terms he uses daily.","tips":["Speak his dialect: coverage, committed deals, slippage.","Anchor confidence to something inspectable: which deals the forecast leans on.","Name the watch item: the two deals that swing the number."],"focus":["audience","precision"],"placeholder":"The forecast holds if we close what's currently in late stages — coverage is solid at"},
    {"id":"audience-fin-mid-25","level":"mid","profession":"finance","title":"Teaching the analyst to leave out the bridge","scenario":"Your analyst is proud of a 12-step variance bridge and wants to walk the operations director through every step. The director wants three things: the number, the reason, and what to do. The analyst reads brevity as hiding their work.","task":"Write a 2-3 sentence coaching note explaining why less detail serves this reader better.","tips":["Frame it as audience calibration, not effort erasure.","The bridge is the analyst's confidence; the summary is the reader's answer.","Suggest the mechanic: full bridge in the appendix, three sentences on top."],"focus":["audience","structure"]}
  ],
  "structure-that-carries": [
    {"id":"structure-fin-mid-01","level":"mid","profession":"finance","title":"Three buckets for the overspend","scenario":"The department's $220K overspend has eleven contributing line items, and your draft to the CFO's office lists all eleven in the order the ledger shows them. The chief of staff will not read eleven items; she needs a shape she can hold in her head.","task":"Reorganize the eleven drivers into no more than three named groups, each with its subtotal, in 3-4 sentences.","tips":["One governing idea up top: the total and whether it's controllable.","Group by cause (timing, one-offs, run-rate), not by ledger order.","Each bucket gets a name and a number — no orphan line items."],"focus":["structure","clarity"],"placeholder":"The $220K overspend falls into three buckets: timing that reverses ($90K), one-time costs ($80K), and a genuine run-rate increase ($50K)."},
    {"id":"structure-fin-mid-02","level":"mid","profession":"finance","title":"SCQA for the budget-cut memo","scenario":"You need to tell department heads that a company-wide 5% cost reduction is coming and what you need from each of them. Your draft jumps straight to the spreadsheet of targets with no framing, and it reads as an ambush.","task":"Write a 4-sentence opening using situation, complication, question, answer to set up the ask.","tips":["Situation: where the budget stood as everyone understood it.","Complication: what changed to force the 5%.","Question then answer: what each department must now decide, and your proposal."],"focus":["structure","audience"]},
    {"id":"structure-fin-mid-03","level":"mid","profession":"finance","title":"PREP the affordability answer","scenario":"In the budget review the marketing director asks, live, whether she can afford a second campaign this quarter. You know the answer is no without deferring something. You tend to ramble through the numbers before landing.","task":"Write a spoken answer in PREP form (point, reason, example, point) in 3-4 sentences.","tips":["Point first: not without deferring something else.","Reason: the quarter's discretionary budget is already committed.","Example then restate: name what she'd have to move, then repeat the verdict."],"focus":["structure","clarity"],"placeholder":"Not this quarter without a trade-off. Your discretionary budget is already committed to the current campaign;"},
    {"id":"structure-fin-mid-04","level":"mid","profession":"finance","title":"The forecast memo with no spine","scenario":"Your full-year re-forecast memo to the CFO covers revenue, costs, cash, and headcount, but they're interleaved paragraph by paragraph with no headers. The reader can't tell where one topic ends and the next begins.","task":"Write the governing sentence plus four section headers that give the memo a skeleton.","tips":["One governing idea first: the full-year number and the verdict.","Four clean sections, each a noun phrase a reader can navigate by.","Each header should promise one answer, not a topic to explore."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-05","level":"mid","profession":"finance","title":"Grouping the messy spend-request list","scenario":"Seven department heads have sent you pending spend requests totaling $410K, and you're forwarding them to the CFO's office for prioritization. Listed as they arrived, they look like noise. The CFO needs to decide fast.","task":"Regroup the seven requests into 2-3 decision categories and write the framing sentence for each.","tips":["Group by decision, not by requester: must-fund, defer-able, decline.","Lead each group with why it belongs there.","Give each group a subtotal so trade-offs are visible."],"focus":["structure","impact"],"placeholder":"The seven requests sort into three decisions: three are contractually committed ($180K), two can wait to Q4 ($150K), and two I'd decline ($80K)."},
    {"id":"structure-fin-mid-06","level":"mid","profession":"finance","title":"The audit-readiness update","scenario":"You're updating the controller on audit prep. There are things done, things in progress, and one blocker. Your draft is a single flowing paragraph where the blocker is easy to miss in the middle.","task":"Restructure the update into three labeled states (done / in progress / blocked) in 3-4 sentences.","tips":["Lead with the blocker if it needs action — status isn't chronological.","Three states, clearly separated, so nothing hides.","End with the one thing you need from the controller."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-07","level":"mid","profession":"finance","title":"One idea per paragraph","scenario":"Your commentary paragraph for the CFO pack mixes the revenue miss, a cost saving, and a cash-timing note in one dense block. Each is important; together they cancel out into mush.","task":"Split the block into three one-idea sentences, each leading with its point.","tips":["One paragraph, one idea — enforce it.","Order by what matters most to the reader, not by what you wrote first.","Each sentence should survive being read alone."],"focus":["structure","concision"]},
    {"id":"structure-fin-mid-08","level":"mid","profession":"finance","title":"The capex case with no hierarchy","scenario":"Your one-page case for the $500K systems investment lists twelve benefits as equal bullets. The approval committee can't tell the two that actually justify the spend from the ten that are nice-to-haves.","task":"Restructure into one headline benefit and two supporting groups in 3-4 sentences.","tips":["Lead with the single benefit that carries the decision.","Demote the rest into two supporting themes.","A flat list of twelve equals hides the argument — rank it."],"focus":["structure","impact"]},
    {"id":"structure-fin-mid-09","level":"mid","profession":"finance","title":"Framing the two-scenario forecast","scenario":"You're presenting a base case and a downside case for the year to the leadership team. Your draft presents dozens of numbers before revealing there are two scenarios at all, so listeners can't file the figures anywhere.","task":"Write the 2-3 framing sentences that establish the two-scenario structure before any numbers.","tips":["Announce the structure first: two cases, here's what separates them.","Give the reader the filing cabinet before you hand them the files.","Name the single variable that swings base to downside."],"focus":["structure","clarity"],"placeholder":"I'll show two scenarios that differ on one thing — whether the two enterprise renewals close this year."},
    {"id":"structure-fin-mid-10","level":"mid","profession":"finance","title":"The spend-decline that wanders","scenario":"You're declining a facilities upgrade request and your reply meanders: some budget context, a bit of the decision, more context, a maybe, then the actual no. The facilities director finishes unsure whether it's a no.","task":"Rewrite in a clean decision structure: verdict, one reason, path forward — 3 sentences.","tips":["Verdict as its own sentence, unmissable.","One reason, then stop stacking justifications.","Path forward as the close: what would change the answer."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-11","level":"mid","profession":"finance","title":"Pyramid for the quarterly review deck","scenario":"You're building the three-slide finance section for the quarterly business review. Right now it's a chronological walk through the P&L. Leadership wants the argument, not the tour.","task":"Write the governing statement and the three supporting points that become your three slides.","tips":["One governing statement the whole section proves.","Three supports, each a slide, each independently true.","If a support doesn't back the governing idea, it's a different deck."],"focus":["structure","impact"],"placeholder":"Governing idea: we'll hit the full-year number, but only if two risks are managed."},
    {"id":"structure-fin-mid-12","level":"mid","profession":"finance","title":"The reconciliation walkthrough","scenario":"You're explaining to a department head why her reported number differs from what her own tracker shows. There are four reconciling items. Your draft lists them in random order and she gets lost after the second.","task":"Structure the four items from largest to smallest with a running total, in 3-4 sentences.","tips":["Order by size so the big movers land first.","Show the running total so she can follow the math to the answer.","End on the reconciled number, stated plainly."],"focus":["structure","precision"]},
    {"id":"structure-fin-mid-13","level":"mid","profession":"finance","title":"Signposting the long email","scenario":"Your email to the operations director covers three separate decisions he needs to make about his budget. Without signposting, he'll act on the first and forget the other two.","task":"Add an opening line that enumerates the three decisions, then structure the body to match.","tips":["Tell him up front: three decisions in this email.","Number them, and let the body headers echo the numbers.","A reader who knows the shape reads for completion, not just to the first ask."],"focus":["structure","clarity"],"placeholder":"Three decisions in this email: (1) the contractor extension, (2) the deferred hire, and (3) the Q4 contingency."},
    {"id":"structure-fin-mid-14","level":"mid","profession":"finance","title":"The risk register nobody can scan","scenario":"You maintain a list of eight budget risks for the CFO's office. It's a flat list with no sense of which are urgent. The CFO's chief of staff asks you to make it usable in one glance.","task":"Restructure the eight risks into a by-severity grouping and write the one-line intro.","tips":["Group by severity or likelihood, not by department.","Lead with the group that needs a decision now.","Each risk: one line, with owner and the trigger to watch."],"focus":["structure","concision"]},
    {"id":"structure-fin-mid-15","level":"mid","profession":"finance","title":"PREP under a hallway question","scenario":"Walking to a meeting, the CFO asks whether the cost-savings program will hit its target. You know it's tracking short by about $200K. You tend to launch into the tabs of your tracker.","task":"Give the spoken PREP answer in 3-4 sentences: point, reason, example, point.","tips":["Point: we'll land about $200K short of target.","Reason: two initiatives slipped to next year.","Example then restate: name them, then repeat the shortfall clearly."],"focus":["structure","concision"]},
    {"id":"structure-fin-mid-16","level":"mid","profession":"finance","title":"The onboarding doc with no path","scenario":"You're writing the 'how budgeting works here' doc for new department heads. Your draft is a wall of policies in no particular order. A new director needs a sequence: what to do first, second, third.","task":"Rewrite the opening as a numbered sequence of the first three things a new director must do.","tips":["Order by the reader's timeline, not the policy's importance to you.","Three concrete first actions, each with a deadline.","Reference material comes after the sequence, not woven through it."],"focus":["structure","audience"]},
    {"id":"structure-fin-mid-17","level":"mid","profession":"finance","title":"The board-slide bullet salad","scenario":"Your finance summary slide for the board has nine bullets at one level, covering revenue, cost, cash, and risk all mixed together. A board member has thirty seconds and no way in.","task":"Regroup the nine bullets under 2-3 headers and write those headers.","tips":["Group into a small number of labeled themes.","Headers should answer 'how are we doing on X,' not name a topic.","Nine flat bullets is data; grouped, it's a message."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-18","level":"mid","profession":"finance","title":"The 'walk me through it' request","scenario":"The new sales VP asks you to walk him through how his budget is built. There's a logical chain — headcount drives salary, salary plus travel plus tools gives the total, minus timing gives the phasing. Your draft jumps between links.","task":"Write the explanation as an ordered chain of 3-4 steps he can follow.","tips":["Build it in order so each step rests on the last.","One link per sentence; no jumping ahead.","End at the number he sees on his dashboard, so it connects."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-19","level":"mid","profession":"finance","title":"Separating decisions from FYIs","scenario":"Your weekly note to the CFO's office bundles items needing a decision with pure updates, all in one list. Decisions get buried among FYIs and slip.","task":"Split the note into two clearly labeled sections — decisions needed and for information — with a line under each.","tips":["Two headers: 'Decisions needed' and 'For information.'","Put decisions first; they carry a deadline, FYIs don't.","A reader should never hunt for what's being asked of them."],"focus":["structure","impact"],"placeholder":"Decisions needed by Friday: (1) release or hold the $250K contingency. For information:"},
    {"id":"structure-fin-mid-20","level":"mid","profession":"finance","title":"The variance story arc","scenario":"You're explaining a $150K favorable variance to the CFO's office, and the honest story is that $120K is timing that will reverse next month while only $30K is real. Told flat, it reads as a $150K win that isn't there.","task":"Structure the explanation so the reader lands on the real $30K, not the headline $150K, in 3 sentences.","tips":["Lead with the headline, then immediately split it.","Structure toward the number that survives next month.","End on the durable figure so that's what they remember."],"focus":["structure","precision"]},
    {"id":"structure-fin-mid-21","level":"mid","profession":"finance","title":"Coaching structure into the analyst's memo","scenario":"Your analyst's cost-review memo has good content but no architecture: findings, background, more findings, a recommendation, then more background. You want to teach the shape, not just fix this one.","task":"Write a 3-4 sentence coaching note naming the structure you want and why.","tips":["Name a reusable pattern: answer, then three supports, then detail.","Explain the reader's read: top-down, stopping when satisfied.","Give one concrete move to make on this draft now."],"focus":["structure","audience"]},
    {"id":"structure-fin-mid-22","level":"mid","profession":"finance","title":"The three-option decision paper","scenario":"To close a budget gap, the CFO's office has three options: cut a program, defer hires, or draw contingency. Your paper describes each at length but never puts them side by side, so they can't be compared.","task":"Restructure into a parallel three-option format — same three attributes for each — and write the framing line.","tips":["Parallel structure: compare each option on the same axes.","Same order of attributes for all three so the eye can scan across.","Add your recommendation after the comparison, not instead of it."],"focus":["structure","impact"],"placeholder":"Three options, each scored on savings, risk, and reversibility:"},
    {"id":"structure-fin-mid-23","level":"mid","profession":"finance","title":"The close-timeline update","scenario":"Month-end close has five stages and you're updating the CFO's office on where it stands. Your draft mentions stages out of order and mixes in caveats, so no one can tell if close is on time.","task":"Structure the update as the five stages in sequence with a clear on-time/at-risk flag on each — 3-4 sentences.","tips":["Sequence matters here — present stages in the order they run.","Flag each as on-track or at-risk so the reader scans the exceptions.","Lead the summary line with the bottom line: on time or not."],"focus":["structure","clarity"]},
    {"id":"structure-fin-mid-24","level":"mid","profession":"finance","title":"One governing idea for the town-hall slide","scenario":"You've been asked to give the finance update at the company town hall: two minutes, one slide, a general-staff audience. Your draft crams five messages on. People will remember none of them.","task":"Choose the single governing message and write it plus the two facts that support it — 3 sentences.","tips":["One message people can repeat at lunch — pick it.","Two supporting facts, no more; the slide has a memory budget.","Cut anything that doesn't serve the one message, however true."],"focus":["structure","concision"]},
    {"id":"structure-fin-mid-25","level":"mid","profession":"finance","title":"Reordering the risk escalation","scenario":"You're escalating three budget risks to the CFO. Your draft presents them in the order you discovered them, which puts the most serious one — a potential $500K shortfall — last. By then the reader's attention is spent.","task":"Reorder the three risks by severity and write the one-line lead that frames the set — 3 sentences.","tips":["Severity, not chronology, decides order in an escalation.","Lead line names the count and the worst one.","Each risk gets its own sentence: what, how big, what you need."],"focus":["structure","impact"],"placeholder":"Three risks, worst first: a possible $500K revenue shortfall if the two renewals slip,"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-fin-mid-01","level":"mid","profession":"finance","title":"The over-hedged forecast note","scenario":"Your forecast note reads: 'It would appear that we may possibly see some degree of softening in revenue, though it's still relatively early to say with any real certainty.' The CFO's office can't tell if you're worried or not.","task":"Rewrite it as one clean sentence that states the view and its confidence.","tips":["Strip the hedge stack: 'appear,' 'may possibly,' 'some degree,' 'relatively.'","State the view, then one honest confidence marker.","One hedge is candor; five is evasion."],"focus":["concision","clarity"],"placeholder":"Revenue is softening — I'd put it at 3% below plan, with the enterprise renewals the main uncertainty."},
    {"id":"concise-fin-mid-02","level":"mid","profession":"finance","title":"Nominalizations in the budget memo","scenario":"Your memo says 'the implementation of a reduction in discretionary expenditure will be undertaken by department heads.' Buried in the noun-heavy phrasing is a simple instruction.","task":"Rewrite it as a direct sentence with a real verb.","tips":["Turn nouns back into verbs: 'implementation of a reduction' becomes 'cut.'","Name who does what: department heads cut.","Shorter isn't the goal; direct is — short follows."],"focus":["concision","clarity"],"placeholder":"Department heads will cut discretionary spend by 5%."},
    {"id":"concise-fin-mid-03","level":"mid","profession":"finance","title":"Halving the variance paragraph","scenario":"Your variance commentary runs 140 words to say the department is $60K over because of one late-signed contract. The CFO pack has a strict word budget and yours is triple what it needs.","task":"Cut the paragraph to under 40 words without losing the driver or the number.","tips":["Keep the number, the cause, and the outlook; cut the rest.","Delete any sentence that restates another.","If a phrase can go without changing the meaning, it goes."],"focus":["concision","precision"]},
    {"id":"concise-fin-mid-04","level":"mid","profession":"finance","title":"The meta-commentary opener","scenario":"Your email to the operations director opens: 'I wanted to reach out and take a moment to touch base regarding a few thoughts I've been having about the budget situation.' Three lines in, you haven't said anything.","task":"Delete the throat-clearing and write the real first sentence.","tips":["Cut 'I wanted to,' 'take a moment,' 'touch base,' 'a few thoughts.'","Start where the content starts.","The reader's clock started at word one — don't waste it."],"focus":["concision","clarity"],"placeholder":"Your Q3 budget has $40K of room — here's what I'd do with it."},
    {"id":"concise-fin-mid-05","level":"mid","profession":"finance","title":"Redundant pairs in the policy line","scenario":"Your spend-policy update reads 'each and every request must be reviewed and evaluated by finance in a timely and prompt manner.' The doublets add length, not meaning.","task":"Rewrite the sentence, collapsing each redundant pair to one word.","tips":["'Each and every' is 'every.' 'Reviewed and evaluated' is 'reviewed.'","'Timely and prompt' is one idea — pick a real deadline instead.","Vague speed words hide a missing number; add the number."],"focus":["concision","precision"],"placeholder":"Finance reviews every request within two business days."},
    {"id":"concise-fin-mid-06","level":"mid","profession":"finance","title":"The Slack reply that buries the yes","scenario":"A department head asks on Slack if she can move $10K between line items. The answer is a simple yes, but your draft reply is five sentences of context about budget flexibility before it.","task":"Write the one-line reply that gives the yes and the one condition.","tips":["Lead with 'yes' — she asked a yes/no question.","One condition, if any, attached to the yes.","Save the budget-flexibility lecture; she didn't ask for it."],"focus":["concision","clarity"],"placeholder":"Yes — move it freely within your discretionary lines, just email me the reallocation so I can update the tracker."},
    {"id":"concise-fin-mid-07","level":"mid","profession":"finance","title":"Filler in the audit-status line","scenario":"You report to the controller: 'At this point in time, it's basically the case that we are, for all intents and purposes, essentially on track with the audit.' The filler drowns a simple status.","task":"Rewrite as a short, direct status sentence.","tips":["Delete 'at this point in time,' 'basically,' 'for all intents and purposes,' 'essentially.'","Say the status and name any exception.","Filler is where confidence goes to hide."],"focus":["concision","clarity"],"placeholder":"The audit is on track; the one open item is the payroll sample, due Friday."},
    {"id":"concise-fin-mid-08","level":"mid","profession":"finance","title":"Trimming the decline","scenario":"Your reply declining a $25K spend request runs seven sentences, most of them cushioning. The requester has to read to sentence six to learn it's a no.","task":"Cut it to three sentences: no, one reason, path forward.","tips":["The no can't be earned by more preamble — state it.","One reason carries more weight than three.","Cushioning that delays the answer isn't kindness; it's suspense."],"focus":["concision","impact"]},
    {"id":"concise-fin-mid-09","level":"mid","profession":"finance","title":"The over-explained accrual","scenario":"A department head asks why an expense showed up early. Your reply is three paragraphs on accrual accounting theory. She needed one sentence and got a lecture.","task":"Compress the answer to two sentences a busy non-finance leader will actually read.","tips":["Answer the question asked, not the one you find interesting.","Costs count when they happen, not when the bill arrives — one sentence.","Depth on request; brevity by default."],"focus":["concision","audience"]},
    {"id":"concise-fin-mid-10","level":"mid","profession":"finance","title":"The bloated board bullet","scenario":"A board-slide bullet reads: 'We are continuing to make ongoing progress toward the achievement of our previously stated cost-reduction objectives.' It says nothing measurable.","task":"Rewrite the bullet with a number and no filler, under 12 words.","tips":["Replace 'making progress toward' with the actual figure.","Cut 'continuing,' 'ongoing,' 'previously stated.'","A board bullet with no number is a placeholder."],"focus":["concision","precision"],"placeholder":"Cost savings: $1.1M locked, $0.4M to go, on track for year-end."},
    {"id":"concise-fin-mid-11","level":"mid","profession":"finance","title":"The re-forecast email that repeats itself","scenario":"Your re-forecast email makes the same point — revenue is 4% light — in the opening, the middle, and the close, each time reworded. The reader gets it the first time.","task":"Rewrite so the point appears once, sharply, and the rest adds new information.","tips":["State the headline once, then only add: drivers, outlook, ask.","Delete every restatement that carries no new fact.","Repetition reads as padding, not emphasis."],"focus":["concision","structure"]},
    {"id":"concise-fin-mid-12","level":"mid","profession":"finance","title":"Qualifier creep in the recommendation","scenario":"Your capex recommendation reads 'I would tentatively suggest that we might want to consider potentially moving forward with the purchase.' Five qualifiers turn a recommendation into a shrug.","task":"Rewrite it as a recommendation that actually recommends, in one sentence.","tips":["Cut 'tentatively,' 'suggest,' 'might want to,' 'consider,' 'potentially.'","Own the call: 'I recommend approving.'","Uncertainty belongs in the reasons, not smeared across the verb."],"focus":["concision","impact"],"placeholder":"I recommend approving the purchase; it pays back in under two years."},
    {"id":"concise-fin-mid-13","level":"mid","profession":"finance","title":"The 90-word cash update in 30","scenario":"Your cash update to the CFO's office is 90 words describing collections, timing, and a $400K swing. The chief of staff wants the version she can read on her phone between meetings.","task":"Cut it to under 30 words that keep the number, the direction, and the cause.","tips":["Number, direction, cause — everything else is optional.","Merge sentences that share a subject.","Test it: could she act on it from the lock screen?"],"focus":["concision","precision"]},
    {"id":"concise-fin-mid-14","level":"mid","profession":"finance","title":"The passive audit finding","scenario":"Your write-up says 'it was determined that certain invoices had been processed without the requisite approvals having been obtained.' The passive voice hides who and what.","task":"Rewrite in active voice, naming the process and the fix in one or two sentences.","tips":["Active voice names the actor: procurement approved invoices without POs.","'It was determined' — by whom? Say it or cut it.","Passive constructions add words and remove accountability."],"focus":["concision","clarity"]},
    {"id":"concise-fin-mid-15","level":"mid","profession":"finance","title":"Trimming the reminder","scenario":"Your accrual-deadline reminder runs four sentences of apology and context before the date. Department heads skim to find the number and the deadline; make them the message.","task":"Rewrite as a two-sentence reminder: what's due, by when.","tips":["Cut the apology; a deadline reminder isn't an imposition.","Date and deliverable in sentence one.","One link for the mechanics, not a paragraph."],"focus":["concision","clarity"],"placeholder":"Q2 accruals are due by the 25th — submit via the usual template here."},
    {"id":"concise-fin-mid-16","level":"mid","profession":"finance","title":"The presentation intro that stalls","scenario":"You open the budget review by explaining what you're about to explain: 'Today I'll walk through several areas, starting with an overview, then some detail, before getting into the main points.' Ninety seconds gone, no content.","task":"Replace the meta-preview with a direct opening that starts on substance.","tips":["Don't describe the talk — give it.","One sentence of framing at most, then the first real point.","Announce the destination, not the itinerary."],"focus":["concision","structure"]},
    {"id":"concise-fin-mid-17","level":"mid","profession":"finance","title":"The spend-approval with three restatements","scenario":"Your approval message says the request is approved, then that it's been signed off, then that you're happy to green-light it. Three ways to say yes, plus the conditions scattered between them.","task":"Rewrite as one approval sentence with the conditions consolidated after it.","tips":["Say yes once.","Gather the conditions into one place, not sprinkled around.","Repetition of 'approved' doesn't make it more approved."],"focus":["concision","clarity"]},
    {"id":"concise-fin-mid-18","level":"mid","profession":"finance","title":"Cutting the analyst's throat-clearing","scenario":"Your analyst's commentary opens every paragraph with 'It is worth noting that' or 'It should be mentioned that.' The stems add words and delay every point.","task":"Write a 2-sentence coaching note plus a rewritten example line that drops the stems.","tips":["'It is worth noting that X' is just 'X.'","Show the before/after on one line so the fix is concrete.","Every deleted stem moves the point three words earlier."],"focus":["concision","clarity"]},
    {"id":"concise-fin-mid-19","level":"mid","profession":"finance","title":"The over-caveated risk flag","scenario":"You're flagging a risk to the CFO's office but wrap it in so many 'this may or may not materialize' caveats that it reads as ignorable. It isn't — it's a real $300K exposure.","task":"Rewrite so the risk is stated cleanly with a single, honest confidence marker.","tips":["State the exposure and its size first.","One confidence statement: likely, possible, or unlikely — pick one.","Over-caveating a real risk is how it gets missed."],"focus":["concision","impact"],"placeholder":"There's a real $300K exposure if the vendor dispute goes against us — I'd call it more likely than not."},
    {"id":"concise-fin-mid-20","level":"mid","profession":"finance","title":"The wordy chase","scenario":"Your third follow-up for the missing budget template opens with two sentences of apology and context. You need the template; the words around the ask make it easier to ignore.","task":"Rewrite as a one-line chase: what you need, by when.","tips":["Cut the apology and the 'just following up.'","The ask and the date, nothing else.","A clear, short chase is easier to act on than a soft, long one."],"focus":["concision","impact"]},
    {"id":"concise-fin-mid-21","level":"mid","profession":"finance","title":"The abstraction ladder","scenario":"Your memo says 'there are certain challenges in the area of cost management that warrant attention going forward.' Every noun is abstract; nothing concrete survives.","task":"Rewrite it naming the actual cost, the actual number, and the actual action.","tips":["Replace 'certain challenges' with the specific cost that's rising.","'Warrant attention' means someone should do something — say what.","Abstraction is where budgets go to die; get concrete."],"focus":["concision","precision"],"placeholder":"Contractor spend is up 30% ($120K) this year; I want to cap new engagements above $20K."},
    {"id":"concise-fin-mid-22","level":"mid","profession":"finance","title":"Two sentences from a paragraph","scenario":"Your update on the systems-migration budget is a dense paragraph. The controller only needs to know: it's on budget, and one risk could add $50K. Everything else is detail he'll ask for if he wants it.","task":"Compress the paragraph to two sentences carrying the status and the one risk.","tips":["On budget — say it plainly, first.","The one risk with its number, second.","Detail is available on request; lead with the two facts that matter."],"focus":["concision","precision"]},
    {"id":"concise-fin-mid-23","level":"mid","profession":"finance","title":"The intensifier stack","scenario":"Your note to the CFO says the overspend is 'extremely significant and really quite substantial, a very major concern.' Four intensifiers and still no number.","task":"Rewrite it with the number replacing the intensifiers.","tips":["'Extremely significant' means nothing without a figure.","One number ends the argument the adjectives were trying to have.","Delete every 'very,' 'really,' 'quite,' 'extremely.'"],"focus":["concision","precision"],"placeholder":"The overspend is $420K — 18% over the department's full-year budget."},
    {"id":"concise-fin-mid-24","level":"mid","profession":"finance","title":"The self-referential close","scenario":"Your budget email ends: 'I hope this email has been helpful in clarifying the situation and please do not hesitate to reach out if you have any questions or concerns whatsoever.' Boilerplate that adds nothing.","task":"Replace the close with one useful sentence or none.","tips":["'Don't hesitate to reach out' is filler — cut or make it specific.","If there's a next step, name it; if not, stop.","A crisp email doesn't need a soft landing."],"focus":["concision","clarity"]},
    {"id":"concise-fin-mid-25","level":"mid","profession":"finance","title":"Tightening the spoken update","scenario":"You practice your 30-second re-forecast update aloud and it runs 70 seconds, thick with 'sort of,' 'kind of,' and 'you know.' The CFO's office gave you thirty seconds for a reason.","task":"Rewrite the spoken update to land in 30 seconds, cutting every verbal-filler crutch.","tips":["Read it aloud and delete every 'sort of,' 'kind of,' 'you know.'","Spoken filler is the ear's version of hedging — cut it.","Shorter spoken answers sound more, not less, confident."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-fin-mid-01","level":"mid","profession":"finance","title":"'Costs are up a lot'","scenario":"Your draft to the CFO's office says contractor costs are 'up a lot' this quarter and 'trending in the wrong direction.' The chief of staff will ask 'how much?' before she does anything with it.","task":"Rewrite the sentence with the percentage, the dollar figure, and the comparison base.","tips":["Replace 'a lot' with the number and the base it's measured against.","'Up 30% vs. plan' beats 'up a lot' every time.","Add the dollar figure so the reader can size it against the budget."],"focus":["precision","clarity"],"placeholder":"Contractor costs are up 30% versus plan this quarter — $120K over — driven by two extended engagements."},
    {"id":"precision-fin-mid-02","level":"mid","profession":"finance","title":"'Soon' isn't a date","scenario":"You told the operations director his budget correction 'will be reflected soon' and the reconciliation 'should be done shortly.' He's planning around your vague timeline and it's biting him.","task":"Rewrite with specific dates for both the correction and the reconciliation.","tips":["'Soon' and 'shortly' are promises with no accountability — date them.","Give the date the correction appears in his numbers.","If you can't commit a date, commit a date to give him one."],"focus":["precision","clarity"],"placeholder":"The correction will appear in your March numbers, posted by April 5; the full reconciliation is done by April 2."},
    {"id":"precision-fin-mid-03","level":"mid","profession":"finance","title":"From the table to the insight","scenario":"You've handed the marketing director a table of her twelve months of spend. She stares at it. What she needs is the one thing the table shows: she's on pace to overspend by $80K unless she slows in Q4.","task":"Write the one-sentence insight the table proves, with the number.","tips":["Data isn't a message; the message is what the data means.","One insight, quantified: the trajectory and the endpoint.","The table is the evidence; give her the verdict."],"focus":["precision","impact"],"placeholder":"At your current pace you'll end the year $80K over — enough that Q4 needs to run 15% lighter."},
    {"id":"precision-fin-mid-04","level":"mid","profession":"finance","title":"What, so what, now what","scenario":"You've noticed the department's cloud costs rose from $40K to $58K a month over the quarter. Your draft states the rise and stops. The CFO's office needs the 'so what' and the 'now what' too.","task":"Write three sentences: the fact, why it matters, what to do.","tips":["What: the rise, with both numbers.","So what: annualized, that's $216K of unplanned run-rate.","Now what: the specific action — cap, review, or renegotiate."],"focus":["precision","structure"],"placeholder":"Cloud costs rose from $40K to $58K a month this quarter. Annualized, that's $216K of new run-rate. I want to review the two services driving it before it compounds."},
    {"id":"precision-fin-mid-05","level":"mid","profession":"finance","title":"The skeptic test on your forecast","scenario":"You forecast revenue landing 'roughly at plan.' A skeptical CFO will ask what 'roughly' hides and which assumptions carry it. Your draft has no evidence a doubter would accept.","task":"Rewrite the claim with the range, the key assumption, and what would break it.","tips":["'Roughly at plan' hides a range — state it.","Name the one or two assumptions the number rests on.","Say what would move it, so the skeptic sees you've thought about it."],"focus":["precision","impact"]},
    {"id":"precision-fin-mid-06","level":"mid","profession":"finance","title":"'Significant savings'","scenario":"Your capex case claims the new system will deliver 'significant savings' and 'improved efficiency.' The approval committee has heard those words on every request; they mean nothing without figures.","task":"Rewrite the benefit sentence with the annual dollar saving and the payback period.","tips":["'Significant' is the word people use when they don't have the number.","Give the annual saving and the payback in months.","'Improved efficiency' — in what, measured how? Quantify or cut."],"focus":["precision","impact"],"placeholder":"The system saves an estimated $180K a year in manual processing, paying back the $500K cost in 33 months."},
    {"id":"precision-fin-mid-07","level":"mid","profession":"finance","title":"Dating the risk","scenario":"You flag to the CFO's office that a vendor contract 'may become a problem in the near future.' Near future could be next week or next year, and the response differs entirely.","task":"Rewrite naming the specific date the risk triggers and the exposure at that point.","tips":["'Near future' — put a date on it: the auto-renewal is the 30th.","State the exposure if nothing is done by then.","A dated risk gets acted on; an undated one gets filed."],"focus":["precision","clarity"],"placeholder":"The contract auto-renews on the 30th at +18% — $54K of added annual cost — unless we cancel by the 15th."},
    {"id":"precision-fin-mid-08","level":"mid","profession":"finance","title":"'Most departments'","scenario":"Your budget summary says 'most departments are tracking close to plan, though a few are running over.' The CFO's office wants to know which few, and by how much.","task":"Rewrite naming the departments over plan and their variances, in one or two sentences.","tips":["'Most' and 'a few' are dodges — name names and numbers.","The exceptions are the story; lead with them.","Precision here is what turns a summary into something actionable."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-09","level":"mid","profession":"finance","title":"The one number that carries the meeting","scenario":"You're going into the budget review with fifteen data points about the engineering department. Only one matters for the decision: at current hiring pace they'll blow the budget by $300K in Q4. The rest is context.","task":"Write the single sentence built around that number that you'll open with.","tips":["Find the one number the decision turns on and lead with it.","Give it the comparison that makes it land: over budget by how much, by when.","The other fourteen points support this one; don't let them bury it."],"focus":["precision","impact"],"placeholder":"At the current hiring pace, engineering runs $300K over budget by Q4 — that's the number today's decision has to solve."},
    {"id":"precision-fin-mid-10","level":"mid","profession":"finance","title":"'Better than last quarter'","scenario":"You report to the leadership team that collections are 'better than last quarter.' Better by how much, from what, to what? Without the figures the claim is unfalsifiable and unconvincing.","task":"Rewrite with the before, the after, and the change.","tips":["Comparatives need both anchors: from X to Y.","Give the change in days or dollars, not just 'better.'","Precision is credibility — a vague win reads as no win."],"focus":["precision","clarity"],"placeholder":"Average collection time dropped from 52 days to 44 days this quarter, freeing about $350K of cash."},
    {"id":"precision-fin-mid-11","level":"mid","profession":"finance","title":"Evidence for the decline","scenario":"You're declining a spend request and your reason is 'the budget is tight right now.' The requester can't argue with a vague claim, but they also can't trust it. Show them the actual room.","task":"Rewrite the reason with the specific remaining budget and what's already committed against it.","tips":["'Tight' is a feeling; give the number.","Show remaining discretionary budget and what's already spoken for.","Evidence turns a no from arbitrary into reasonable."],"focus":["precision","impact"],"placeholder":"Your discretionary budget has $18K left, and $15K of that is committed to the deferred training — there's no room for a $25K request."},
    {"id":"precision-fin-mid-12","level":"mid","profession":"finance","title":"The annualization the reader missed","scenario":"A $9K monthly increase in a subscription looks small in the department head's monthly view, so she waved it through. The point she missed: annualized it's $108K, and it recurs every year after.","task":"Write two sentences that reframe the monthly number into its true annual and multi-year weight.","tips":["Small monthly numbers hide large annual ones — do the multiplication for her.","State the annual figure and flag that it recurs.","Precision here is a service: you're sizing what she couldn't see."],"focus":["precision","impact"]},
    {"id":"precision-fin-mid-13","level":"mid","profession":"finance","title":"Confidence, quantified","scenario":"The CFO asks how likely the cost-savings target is to be hit. 'Pretty confident' is your instinct, but it gives her nothing to plan on. You actually think it's about 80%, with the risk concentrated in one initiative.","task":"Rewrite the answer with a confidence level and where the risk sits.","tips":["Turn 'pretty confident' into a number or a band.","Locate the uncertainty: which initiative carries the doubt.","A quantified confidence is a plan; a vague one is a hope."],"focus":["precision","impact"],"placeholder":"I'd put it at about 80% — the doubt is almost entirely the procurement initiative, which is $200K of the $1.5M target."},
    {"id":"precision-fin-mid-14","level":"mid","profession":"finance","title":"The vague accrual estimate","scenario":"You tell the sales director the event accrual is 'an estimate, could move a bit.' He wants to know how much it could move, because his budget planning depends on it. 'A bit' isn't planning-grade.","task":"Rewrite with the estimate, the likely range, and when it firms up.","tips":["'Could move a bit' — give the range: $55K to $65K.","Say when the actual invoice replaces the estimate.","A ranged estimate he can plan on; a vague one he can't."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-15","level":"mid","profession":"finance","title":"Sourcing the number","scenario":"You state in the CFO pack that headcount costs will rise 8% next year. A skeptic asks where the 8% comes from. Your draft has the number but no visible basis, so it reads as a guess.","task":"Rewrite so the 8% carries its source in the same sentence.","tips":["A number with no source is an opinion; attach the basis.","Cite the driver: merit pool plus the approved backfills.","One clause of provenance defuses the skeptic's question before it's asked."],"focus":["precision","impact"],"placeholder":"Headcount costs rise 8% next year — 3% from the approved merit pool and 5% from the four backfills already signed off."},
    {"id":"precision-fin-mid-16","level":"mid","profession":"finance","title":"From 'trending up' to a trajectory","scenario":"Your note says a cost line is 'trending up.' The CFO's office needs the slope: how fast, to what level, by when. 'Trending up' could be a rounding wobble or a runaway.","task":"Rewrite giving the rate of increase and the projected level at year-end.","tips":["A trend needs a slope and an endpoint, not just a direction.","State the monthly rate and where it lands by December.","'Trending up' with numbers is a forecast; without them it's a shrug."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-17","level":"mid","profession":"finance","title":"The unquantified audit exposure","scenario":"You're briefing the controller on an audit issue and say the missing purchase orders are 'a concern.' He needs to know the scale: how many invoices, what dollar value, what's the worst case.","task":"Rewrite with the count of affected invoices, the total value, and the realistic exposure.","tips":["'A concern' has no size — give the count and the dollars.","Separate the total value from the realistic exposure.","Auditors and CFOs act on magnitude, not adjectives."],"focus":["precision","impact"],"placeholder":"Fourteen invoices totaling $95K were approved without POs; the realistic exposure is a control finding, not a loss."},
    {"id":"precision-fin-mid-18","level":"mid","profession":"finance","title":"Coaching numbers into the analyst's draft","scenario":"Your analyst's commentary is full of 'materially,' 'substantially,' and 'notably' with no figures behind them. You want to teach the habit of attaching a number to every qualitative claim.","task":"Write a 2-3 sentence coaching note plus one rewritten example line showing the number added.","tips":["Every 'materially' should be followed by 'by how much.'","Show the fix on a real line from the draft.","The habit: no adjective of size without a figure beside it."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-19","level":"mid","profession":"finance","title":"The comparison with no baseline","scenario":"You report the department is 'ahead of budget,' but you don't say ahead by how much or against which budget — original, revised, or prior year. The reader can't tell if it's noise or news.","task":"Rewrite naming the baseline and the exact gap to it.","tips":["'Ahead of budget' — which budget, by how much?","Name the baseline explicitly: original plan, not revised.","The same result can be a win or a miss depending on the baseline — state it."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-20","level":"mid","profession":"finance","title":"Making the payback tangible","scenario":"You want to approve the $60K automation tool, and the case is strong, but you've written 'it will pay for itself.' The committee needs the mechanism and the timeline, not a slogan.","task":"Rewrite with the specific saving, the source of it, and the months to payback.","tips":["'Pays for itself' is a claim; show the arithmetic.","Name where the saving comes from — hours, licenses, error reduction.","Payback in months, computed, not asserted."],"focus":["precision","impact"],"placeholder":"It saves 20 analyst-hours a month — about $3.5K — so the $60K cost pays back in 17 months."},
    {"id":"precision-fin-mid-21","level":"mid","profession":"finance","title":"The 'few weeks' close estimate","scenario":"The CFO's office asks when the acquisition's numbers will be integrated into reporting. You say 'a few weeks.' They're setting board expectations on your answer and 'a few weeks' won't survive contact.","task":"Rewrite with a specific target date and the one dependency that could move it.","tips":["'A few weeks' becomes a dated milestone.","Name the single dependency that could shift it, so the date has honesty.","A committed date with a caveat beats a vague window."],"focus":["precision","clarity"],"placeholder":"Integrated reporting is ready by March 20, assuming the mapping file arrives from their team by March 6."},
    {"id":"precision-fin-mid-22","level":"mid","profession":"finance","title":"Quantifying the 'small' overage","scenario":"A department head calls her $15K overspend 'small.' Against her $2M budget it is; against the $50K discretionary pool it came from, it's 30%. The right denominator changes the story.","task":"Write two sentences that put the overage against the denominator that matters.","tips":["'Small' depends on the base — pick the one the decision uses.","$15K is 0.7% of the total but 30% of discretionary; say which matters.","Precision about the denominator is precision about the point."],"focus":["precision","clarity"]},
    {"id":"precision-fin-mid-23","level":"mid","profession":"finance","title":"The forecast range instead of a false point","scenario":"You've been giving the CFO's office a single revenue number that implies more precision than you have. The honest answer is a range with a most-likely point and the swing factor named.","task":"Rewrite the forecast as a range with the central estimate and the driver of the spread.","tips":["A false-precision point number invites false confidence.","Give the range, the central estimate, and what moves it.","Naming the swing factor is more useful than hiding it in a single digit."],"focus":["precision","impact"],"placeholder":"Full-year revenue lands between $47M and $50M, most likely $48.5M — the spread is entirely the two enterprise renewals."},
    {"id":"precision-fin-mid-24","level":"mid","profession":"finance","title":"The evidence a decision needs","scenario":"You're recommending the CFO's office release the $250K contingency now. Your draft asserts the risk has passed but shows no evidence. A CFO releasing reserves wants to see why the risk is gone, not be told.","task":"Rewrite the recommendation with the two concrete facts that prove the risk has receded.","tips":["A recommendation to spend reserves needs its evidence attached.","Two specific facts beat one confident assertion.","Show the skeptic what changed, with numbers or dates."],"focus":["precision","impact"]},
    {"id":"precision-fin-mid-25","level":"mid","profession":"finance","title":"The spoken number that needs an anchor","scenario":"In the leadership meeting you say cash is 'down about $400K.' Someone asks 'down from what, and is that bad?' You know it's a timing swing that reverses next month, but your bare number invited alarm.","task":"Rewrite the spoken line so the $400K arrives with its anchor and its meaning.","tips":["A number spoken without context defaults to the worst reading.","Anchor it: down from plan, but timing that reverses in April.","Say the 'is that bad' answer before they have to ask."],"focus":["precision","clarity"],"placeholder":"Cash is about $400K below plan this month, but it's timing — two large receipts land in early April and reverse it."}
  ],
  "executive-presence": [
    {"id":"presence-fin-mid-01","level":"mid","profession":"finance","title":"The neutral menu with no recommendation","scenario":"You've laid out three ways to close the budget gap for the CFO's office — cut a program, defer hires, draw contingency — with pros and cons for each and no view of your own. They asked for your read, not a menu.","task":"Add the recommendation: name which option you'd choose and why, in 2-3 sentences.","tips":["A menu without a recommendation pushes your job onto the reader.","Pick one and say so; the analysis earns you the right to a view.","Give the single reason it beats the others."],"focus":["impact","structure"],"placeholder":"Of the three, I'd defer the two hires to Q3 — it closes the gap without touching a committed program and is fully reversible."},
    {"id":"presence-fin-mid-02","level":"mid","profession":"finance","title":"Signposting the budget-review open","scenario":"You're chairing the quarterly review with the sales director. Your draft opening dives into numbers with no map, so he doesn't know whether this is a status update, a warning, or a negotiation until he's ten minutes in.","task":"Write a 2-3 sentence open that signposts the meeting's purpose and shape.","tips":["Tell him what kind of meeting this is in the first breath.","Preview the two or three things you'll cover, then the decision at the end.","Signposting is presence: it says you're driving, not wandering."],"focus":["structure","impact"]},
    {"id":"presence-fin-mid-03","level":"mid","profession":"finance","title":"Fact and judgment tangled","scenario":"Your risk note to the CFO's office mixes what happened with what you think about it: 'costs rose $80K which is deeply worrying and probably means the program is out of control.' The reader can't separate the fact from your read.","task":"Rewrite splitting the fact from your judgment, each clearly labeled, in 2-3 sentences.","tips":["State the fact cleanly: costs rose $80K.","Then your judgment, marked as such: 'my read is...'","Blurring the two makes both less trustworthy; separating them shows discipline."],"focus":["precision","impact"],"placeholder":"Fact: program costs rose $80K this month, the third monthly rise. My read: this is now a trend, not a blip, and warrants a spending review."},
    {"id":"presence-fin-mid-04","level":"mid","profession":"finance","title":"Owning the forecast call","scenario":"The CFO's office asks whether to hold or cut the full-year target. Your draft recites the arguments both ways and stops short of a recommendation, hedging behind 'it depends.' They want you to own a call.","task":"Write a 2-3 sentence answer that takes a clear position and stands behind it.","tips":["'It depends' is a non-answer when a decision is due — take a side.","State your call, then the condition that would change it.","Owning a call you might revise beats ducking one you should make."],"focus":["impact","clarity"]},
    {"id":"presence-fin-mid-05","level":"mid","profession":"finance","title":"Presence in the room with a doubting director","scenario":"In the budget review the engineering director pushes back hard on your overspend number, and your instinct is to soften and retreat. But the number is right and the review depends on it holding.","task":"Write a 2-3 sentence response that holds your ground with evidence, not defensiveness.","tips":["Stand behind a correct number calmly — no apology, no retreat.","Bring the evidence, not the emotion.","Presence is holding the line without raising your voice."],"focus":["impact","precision"]},
    {"id":"presence-fin-mid-06","level":"mid","profession":"finance","title":"The recommendation you're hedging","scenario":"You've concluded the $500K systems investment should wait a year, but your memo wraps it in so much 'on the other hand' that the CFO's office can't tell what you actually think.","task":"Rewrite the memo's key sentence to state your recommendation plainly, then hold the caveat to one line.","tips":["Lead with the call: hold the investment a year.","One caveat, clearly subordinate, not five that cancel the call.","A recommendation the reader has to reconstruct isn't a recommendation."],"focus":["impact","concision"],"placeholder":"My recommendation is to hold the $500K systems investment until next year. The one thing that would change it:"},
    {"id":"presence-fin-mid-07","level":"mid","profession":"finance","title":"Speaking up in the leadership meeting","scenario":"In the leadership meeting the team is about to approve a hiring plan you know the budget can't support. You've been quiet, hoping someone else raises it. The window to speak is now, in one clear intervention.","task":"Write the 2-3 sentence intervention that raises the issue with authority, not apology.","tips":["Don't preface with 'sorry to interrupt' — the point earns the interruption.","State the conflict plainly: the plan and the budget don't reconcile.","Offer the fix or the question, so you're constructive, not just blocking."],"focus":["impact","clarity"]},
    {"id":"presence-fin-mid-08","level":"mid","profession":"finance","title":"The apology that undercuts the number","scenario":"You're presenting a variance you're confident in, but your draft opens 'sorry, I know this is probably not what you wanted to see, and I might be wrong but...' The apology erodes a number that doesn't need one.","task":"Rewrite the opening to present the number with quiet confidence and no apology.","tips":["A correct number doesn't need an apology attached.","Cut 'sorry,' 'probably,' 'I might be wrong.'","Deliver the fact, then your read — steadily."],"focus":["impact","concision"]},
    {"id":"presence-fin-mid-09","level":"mid","profession":"finance","title":"Recommending against the popular option","scenario":"Everyone in the room wants to release the contingency now, and you think it should be held. The easy move is to go along. Presence is stating your dissent clearly and giving them the reason.","task":"Write a 2-3 sentence dissent that recommends holding, with the reason, without picking a fight.","tips":["Disagree with the room on substance, calmly.","Lead with your recommendation, then the risk that drives it.","Respect the room's view while holding your own — both can be true."],"focus":["impact","structure"],"placeholder":"I know the room wants to release it, and I'd hold the contingency until Q4 — the forecast still has a $300K downside that hasn't cleared."},
    {"id":"presence-fin-mid-10","level":"mid","profession":"finance","title":"The status update that reads as a to-do list","scenario":"Your update to the CFO's office lists twelve tasks in progress with no sense of what's under control and what needs their attention. It reads as busy, not as in-command.","task":"Rewrite as a 3-sentence update that leads with the bottom line and flags only what needs them.","tips":["Lead with the verdict: on track, one issue.","Demote the twelve tasks to 'everything else is on plan.'","Presence is showing you know which one thing matters."],"focus":["impact","structure"]},
    {"id":"presence-fin-mid-11","level":"mid","profession":"finance","title":"Committing to a number under scrutiny","scenario":"The CFO asks you point-blank in front of the leadership team what the year-end cash position will be. You have a good estimate but want to hide behind ranges and caveats. They want a number you'll stand behind.","task":"Write the 2-3 sentence answer that commits to a figure and names your confidence honestly.","tips":["Give the number first; the range can follow.","Commit, then caveat — not the reverse.","Confidence isn't certainty; it's willingness to be held to a figure."],"focus":["impact","precision"],"placeholder":"I expect year-end cash around $4.2M. I'm confident to within $200K; the swing is the timing of the December receivable."},
    {"id":"presence-fin-mid-12","level":"mid","profession":"finance","title":"The recommendation buried in the appendix","scenario":"Your decision paper for the CFO's office puts a clear recommendation on the last page after eleven pages of analysis. Executives read the front; your best thinking is where they'll never reach.","task":"Write the front-page recommendation box — 2-3 sentences — that should open the paper.","tips":["Your recommendation belongs on page one, not page twelve.","State the call, the reason, and the decision needed.","Analysis supports the recommendation; it shouldn't hide it."],"focus":["impact","structure"]},
    {"id":"presence-fin-mid-13","level":"mid","profession":"finance","title":"Presence over Slack","scenario":"The CFO Slacks you at 8pm asking if the department can absorb an unplanned $100K cost. You could ask for time, or you could give a confident, caveated answer now. The moment rewards a clear read.","task":"Write the 2-3 sentence Slack reply that gives a real answer with appropriate confidence.","tips":["A same-evening confident answer builds trust; endless deferral doesn't.","Give your best read now, marked as preliminary if it must be.","Name what you'd confirm tomorrow, so the caveat is specific."],"focus":["impact","clarity"],"placeholder":"Best read tonight: yes, we can absorb it by trimming the deferred training and the Q4 contingency — I'll confirm the exact mix in the morning."},
    {"id":"presence-fin-mid-14","level":"mid","profession":"finance","title":"The over-qualified risk brief","scenario":"You're briefing the CFO's chief of staff on a risk and every sentence is hedged — 'possibly,' 'it could be argued,' 'one might say.' She can't tell whether you're worried or just covering yourself.","task":"Rewrite the brief to state your actual assessment with one honest confidence level.","tips":["Say what you think, once, plainly.","Replace the hedge-carpet with a single confidence marker.","Covering yourself and informing the reader are different jobs — do the second."],"focus":["impact","concision"]},
    {"id":"presence-fin-mid-15","level":"mid","profession":"finance","title":"Standing behind an unpopular forecast","scenario":"Your re-forecast shows a miss the leadership team doesn't want to hear, and in the meeting they push you to 'find a way to a better number.' The number is honest. Presence is not caving.","task":"Write the 2-3 sentence response that holds the forecast and offers the real levers instead of a nicer number.","tips":["Don't negotiate the number; negotiate the actions that could change it.","Hold the forecast as your honest read, calmly.","Redirect to what would actually move it, not to wishful math."],"focus":["impact","clarity"],"placeholder":"I can't move the forecast to a number I don't believe — but here are two actions that would genuinely close part of the gap:"},
    {"id":"presence-fin-mid-16","level":"mid","profession":"finance","title":"The chair who won't chair","scenario":"You're running the spend-prioritization meeting but your draft agenda and open are passive — 'we could maybe look at some of the requests.' The room needs someone to drive, and that's your job today.","task":"Write a 2-3 sentence open that takes command: purpose, process, and the decision you'll reach.","tips":["Own the room from the first sentence.","State the goal and how you'll get there in the time.","'We could maybe' abdicates; 'here's what we'll decide' leads."],"focus":["impact","structure"]},
    {"id":"presence-fin-mid-17","level":"mid","profession":"finance","title":"Judgment the CFO actually wants","scenario":"You've sent the CFO's office a flawless data pack with no interpretation. The chief of staff replies: 'But what do you think we should do?' They have analysts for data; they need your judgment.","task":"Write the 2-3 sentence judgment layer that should have topped the pack.","tips":["Data is the input; judgment is the value you add.","State what you'd do and the one fact that decides it.","At this level, withholding your view isn't neutrality — it's absence."],"focus":["impact","structure"],"placeholder":"My read: we're fine on the year, but the contractor run-rate is the one thing I'd act on now —"},
    {"id":"presence-fin-mid-18","level":"mid","profession":"finance","title":"Coaching an analyst to take a position","scenario":"Your analyst writes beautiful neutral analysis and never says what she thinks should happen. You want her to start ending memos with a recommendation she owns, not just options she lists.","task":"Write a 2-3 sentence coaching note on why and how to add a recommendation.","tips":["Explain the value: analysis earns her the right to a view — she should use it.","Give the mechanic: end every memo with 'I recommend X because Y.'","Reassure her a well-reasoned wrong call beats a safe non-answer."],"focus":["impact","audience"]},
    {"id":"presence-fin-mid-19","level":"mid","profession":"finance","title":"The confident 'no' to a senior request","scenario":"A senior VP asks you to reclassify an expense in a way that isn't defensible. You need to decline someone above you in the hierarchy, clearly, without either caving or picking a fight.","task":"Write a 2-3 sentence reply that declines firmly, explains the line, and offers a legitimate alternative.","tips":["Decline on principle, not on personality.","Name the line plainly: this wouldn't survive audit.","Offer the legitimate path, so you're solving, not just blocking."],"focus":["impact","clarity"]},
    {"id":"presence-fin-mid-20","level":"mid","profession":"finance","title":"Presence in the one-line answer","scenario":"The CFO's office asks, mid-thread, 'Are we going to hit the number or not?' A paragraph of context reads as evasion. A one-line answer with a confidence marker reads as command.","task":"Write the one-line answer that commits and signals confidence.","tips":["The question is binary-ish; answer in kind, then qualify.","One line, a verdict, a confidence word.","Length here reads as hedging; brevity reads as presence."],"focus":["impact","concision"],"placeholder":"Yes — I'm confident we hit the full-year number, with the caveat that it leans on the two Q4 renewals."},
    {"id":"presence-fin-mid-21","level":"mid","profession":"finance","title":"The recommendation with a spine","scenario":"You're recommending the CFO's office decline a $2M capital request from a powerful business unit. The politics push you toward mush. Presence is a clear no with a clear reason that you'll defend.","task":"Write the 2-3 sentence recommendation that declines clearly and gives the one reason that holds.","tips":["A politically hard call still needs to be a call.","One defensible reason beats several soft ones.","State it so the reader knows exactly where you stand."],"focus":["impact","structure"],"placeholder":"I recommend declining the $2M request: the payback exceeds seven years, well outside our threshold, and no scenario I ran brings it inside."},
    {"id":"presence-fin-mid-22","level":"mid","profession":"finance","title":"Separating 'the numbers say' from 'I think'","scenario":"In your leadership-meeting talking points, you attribute your own judgment to 'the numbers' — 'the numbers say we should cut the program.' The numbers describe; the cut is your recommendation. Owning it is stronger.","task":"Rewrite so the fact and your recommendation are cleanly separated and you own the call.","tips":["Numbers show state; people make recommendations — don't hide behind the data.","'The numbers show X; I recommend Y' is honest and stronger.","Owning the call is presence; attributing it to a spreadsheet isn't."],"focus":["impact","precision"]},
    {"id":"presence-fin-mid-23","level":"mid","profession":"finance","title":"The composed answer to a hostile question","scenario":"In a review a director snaps, 'These finance numbers are always wrong.' It's unfair and you feel it. Presence is answering the substance without matching the heat.","task":"Write a 2-3 sentence reply that stays composed, addresses the real concern, and moves forward.","tips":["Don't match the temperature — lower it.","Address the legitimate grain: which number, and let's check it.","Composure under attack is the clearest signal of presence."],"focus":["impact","clarity"]},
    {"id":"presence-fin-mid-24","level":"mid","profession":"finance","title":"Closing the meeting with ownership","scenario":"The budget review reached decisions, but your draft close is vague — 'we'll follow up on some of this.' A meeting that ends without clear ownership unravels by Monday.","task":"Write a 2-3 sentence close that restates the decisions, the owners, and the dates.","tips":["Name each decision, its owner, and its date — no orphans.","'We'll follow up' owns nothing; assign it.","A clean close is presence: you drove it to a result."],"focus":["impact","structure"],"placeholder":"Three decisions today: you defer the two hires to Q3, I release $40K back to your discretionary line by Friday, and we revisit contractor spend at next month's review."},
    {"id":"presence-fin-mid-25","level":"mid","profession":"finance","title":"The spoken recommendation to the CFO","scenario":"You have ninety seconds with the CFO to recommend whether to proceed with a cost-cutting initiative. Your instinct is to lay out the analysis and let them conclude. Ninety seconds demands you lead with the call.","task":"Write the 90-second spoken recommendation: call first, two reasons, the one risk.","tips":["Open with the recommendation, not the journey to it.","Two reasons, then the one honest risk.","Say it aloud — presence is as much in the delivery as the words."],"focus":["impact","structure"],"placeholder":"I'd proceed with the initiative. Two reasons: it locks in $600K a year, and the disruption is contained to one team. The one risk:"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-fin-mid-01","level":"mid","profession":"finance","title":"'Can we afford it?' — answer first","scenario":"In the leadership meeting the CEO turns to you: 'Can we afford the new office lease, yes or no?' Your instinct is to walk through the cash model. He asked a yes/no and wants it first.","task":"Write the 2-3 sentence answer that gives the verdict first, then the one condition.","tips":["Answer the actual question — yes or no — before any model.","One condition attached to the yes, if there is one.","The reasoning can follow; the verdict can't wait."],"focus":["impact","clarity"],"placeholder":"Yes, we can afford it — if we hold the two open hires until Q3. Without that, no."},
    {"id":"pressure-fin-mid-02","level":"mid","profession":"finance","title":"The pushback on your overspend number","scenario":"The marketing director insists your $180K overspend figure is wrong because 'that agency cost was pre-approved.' Pre-approval doesn't change that it's over budget. You need to hold the number with a specific, not defend generally.","task":"Write a 2-3 sentence reply that answers the specific objection with a specific fact.","tips":["Address the exact claim — pre-approval — not a general defense.","Separate the two things: approved and over-budget can both be true.","Bring the specific: approved or not, it wasn't in the plan."],"focus":["precision","impact"]},
    {"id":"pressure-fin-mid-03","level":"mid","profession":"finance","title":"The honest 'I don't know' with a path","scenario":"The CFO asks in the meeting what the tax impact of the restructuring will be. You genuinely don't know — it's outside your area and needs the tax team. Bluffing would be worse than admitting it.","task":"Write the 2-sentence answer that admits the gap and gives a path to the answer.","tips":["'I don't know' is a complete and respectable answer — with a path.","Name who owns it and when you'll have the number.","Bluffing a number you don't have is the real failure."],"focus":["clarity","impact"],"placeholder":"I don't have the tax impact — that's the tax team's model, not mine. I'll have their number to you by Thursday."},
    {"id":"pressure-fin-mid-04","level":"mid","profession":"finance","title":"Answering the question they asked","scenario":"The ops director asks 'why is my department red this month?' and your draft answers a different question — how the RAG status is calculated. Answer his question, which is about the driver, not the mechanism.","task":"Write a 2-3 sentence answer that names the actual driver first.","tips":["He asked 'why red,' not 'how does red work.'","Lead with the driver: the one thing that pushed him over.","Method, if he wants it, comes after the answer."],"focus":["clarity","audience"]},
    {"id":"pressure-fin-mid-05","level":"mid","profession":"finance","title":"The trap question on the forecast","scenario":"A skeptical board member asks, 'So finance has been wrong three quarters running — why should we believe this forecast?' The premise stings but has a grain of truth. Deflecting or getting defensive both lose.","task":"Write a 2-3 sentence reply that concedes what's fair, then earns the forecast's credibility with specifics.","tips":["Acknowledge the fair part without groveling.","Then show what's different this time — a concrete change in method or inputs.","Don't argue the premise; out-evidence it."],"focus":["impact","precision"]},
    {"id":"pressure-fin-mid-06","level":"mid","profession":"finance","title":"Put on the spot for a number you're unsure of","scenario":"In the meeting the CFO asks for the exact contractor spend to date. You have a rough figure but not the precise one, and precision matters here. Guessing risks being quoted; refusing looks unprepared.","task":"Write a 2-sentence reply that gives the reliable range now and commits to the exact figure by a time.","tips":["Give what you're sure of — the range — clearly.","Don't invent precision you don't have.","Commit to the exact number and when it lands."],"focus":["precision","clarity"],"placeholder":"It's between $110K and $120K — I don't want to quote a false precision. I'll send the exact figure within the hour."},
    {"id":"pressure-fin-mid-07","level":"mid","profession":"finance","title":"The director who reopens a closed decision","scenario":"In the review, the engineering director tries to relitigate the hiring freeze that leadership already decided. You need to answer without reopening it and without being dismissive of his frustration.","task":"Write a 2-3 sentence reply that acknowledges his point but holds the closed decision.","tips":["Hear the frustration; don't reopen the ruling.","Restate the decision and where it was made.","Redirect to what's still in his control."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-mid-08","level":"mid","profession":"finance","title":"'Just make the number work'","scenario":"Under pressure in the meeting, a senior leader says 'I'm sure finance can find a way to make the budget balance.' It's a nudge toward numbers that aren't real. You must decline without insubordination.","task":"Write a 2-3 sentence reply that declines to fabricate and redirects to real options.","tips":["Don't accept the framing that finance can conjure numbers.","Name the real levers that could close the gap honestly.","Firm on integrity, collaborative on the fix."],"focus":["impact","clarity"],"placeholder":"I can't make the gap disappear on paper, but I can show you two real ways to close it —"},
    {"id":"pressure-fin-mid-09","level":"mid","profession":"finance","title":"The hostile 'your numbers are wrong'","scenario":"A department head opens the review by declaring your figures are 'just wrong' in front of his team. You believe they're right. You need to answer the challenge with an invitation to specifics, not a shouting match.","task":"Write a 2-3 sentence reply that stays calm and moves to the specific number in dispute.","tips":["Don't defend all numbers; ask which one.","Lower the temperature by getting concrete.","Confidence plus openness beats defensiveness."],"focus":["impact","precision"],"placeholder":"Happy to check any figure — which one looks wrong to you? Let's pull it up and reconcile it now."},
    {"id":"pressure-fin-mid-10","level":"mid","profession":"finance","title":"The follow-up you can't yet answer","scenario":"Presenting the forecast, you're asked what happens to cash if the biggest customer delays payment 60 days. You haven't modeled that exact scenario. You need to answer honestly and usefully in the moment.","task":"Write a 2-3 sentence reply that gives your best directional read now and commits to the modeled answer.","tips":["Give the direction and rough magnitude you're confident of.","Flag clearly that the precise number needs modeling.","Commit to the run and the timing."],"focus":["clarity","precision"]},
    {"id":"pressure-fin-mid-11","level":"mid","profession":"finance","title":"Cornered on your own miss","scenario":"In front of the leadership team the CEO asks why your forecast missed by $340K. It stings, but the answer is clean — one deal slipped. Getting defensive or over-explaining both hurt; own it briefly and move on.","task":"Write a 2-3 sentence answer that owns the miss, names the driver, and states the fix.","tips":["Own it in one clause; don't spread the blame.","One driver, named specifically.","End on what you changed — that's what they actually want."],"focus":["impact","clarity"],"placeholder":"The miss was almost entirely one enterprise deal slipping to Q3 — $310K of the $340K. I've since separated committed from at-risk pipeline in the forecast so it won't repeat."},
    {"id":"pressure-fin-mid-12","level":"mid","profession":"finance","title":"The leading question about a rival department","scenario":"A director asks you pointedly in the meeting whether another department 'is overspending as usual.' It's a trap to draw you into taking sides. You answer with facts, not gossip.","task":"Write a 2-sentence reply that gives the factual position without editorializing about the other team.","tips":["State the fact; skip the judgment the question is fishing for.","Don't take sides between departments — you serve both.","Neutral and factual is the professional answer."],"focus":["clarity","impact"]},
    {"id":"pressure-fin-mid-13","level":"mid","profession":"finance","title":"Pressed to approve on the spot","scenario":"In the hallway a director pushes for an immediate yes on a $40K spend, saying he needs it 'right now.' You need to check the budget before committing. Answer without stalling or capitulating.","task":"Write a 2-sentence reply that neither caves nor stalls — commits to a fast, specific answer.","tips":["Don't approve blind; don't hide behind process either.","Give a real, short timeline for the answer.","A fast 'I'll confirm by 2pm' beats a pressured yes."],"focus":["impact","clarity"],"placeholder":"I'm not going to approve $40K in the hallway, but I'll have you a firm yes or no by 2pm once I check your remaining budget."},
    {"id":"pressure-fin-mid-14","level":"mid","profession":"finance","title":"The auditor's direct question","scenario":"An auditor asks you directly whether the purchase-order controls were followed every time this quarter. You know of the facilities exceptions. You must answer truthfully and completely, not shade it.","task":"Write a 2-3 sentence answer that is fully honest about the exceptions and their handling.","tips":["Never shade an answer to an auditor — full disclosure.","State the exceptions and that they're already flagged and being fixed.","Honesty here protects you; evasion is the real risk."],"focus":["precision","clarity"]},
    {"id":"pressure-fin-mid-15","level":"mid","profession":"finance","title":"The question that assumes a false premise","scenario":"A leader asks 'since we cut the training budget, where did that money go?' But you never cut it — it was rephased. Answering the question as asked would confirm a falsehood.","task":"Write a 2-3 sentence reply that corrects the premise before answering.","tips":["Fix the false premise first — nothing was cut.","Then answer the real question about where the money sits.","Correcting gently beats letting the falsehood stand."],"focus":["clarity","precision"],"placeholder":"The training budget wasn't cut — it was moved to Q3 to match the new vendor schedule, so it's still fully there."},
    {"id":"pressure-fin-mid-16","level":"mid","profession":"finance","title":"Defending a decline under pressure","scenario":"You declined a spend request and the requester escalates in the meeting, listing three reasons you're wrong. You still think the decline is right. Answer each point with substance, not repetition of the no.","task":"Write a 2-3 sentence reply that engages his strongest point specifically and holds the decision.","tips":["Engage his best argument, not the weakest one.","Answer with a fact, not a restated 'no.'","Leave a door: name what would actually change your answer."],"focus":["impact","precision"]},
    {"id":"pressure-fin-mid-17","level":"mid","profession":"finance","title":"The 'give me one number' demand","scenario":"The CFO cuts off your caveated forecast: 'I don't want a range, give me one number for the board.' You have real uncertainty but they need a single figure. Deliver it with the confidence and the caveat compressed.","task":"Write the 2-sentence reply that gives the single number and one honest caveat.","tips":["Give the number they asked for — don't fight the request.","Compress the uncertainty to one clause they can weigh.","One number with a known caveat is more useful than a refused range."],"focus":["precision","impact"],"placeholder":"Forty-eight and a half million. The one thing that could move it is the two enterprise renewals — worth flagging to the board as the swing factor."},
    {"id":"pressure-fin-mid-18","level":"mid","profession":"finance","title":"Interrupted before you finish","scenario":"You're two sentences into explaining a variance and the director cuts in with 'just tell me if I'm in trouble.' The full explanation can wait; answer the fear he just voiced.","task":"Write the 2-sentence answer that responds to what he actually asked, then offers the detail.","tips":["Answer the interruption's real question first: are you in trouble?","Yes or no, then the one fact that qualifies it.","Offer the full explanation as optional, not mandatory."],"focus":["clarity","impact"],"placeholder":"No, you're not in trouble — the quarter's on plan; this month just looks heavy because of a one-time invoice. Want the detail?"},
    {"id":"pressure-fin-mid-19","level":"mid","profession":"finance","title":"The recurring late accruals, challenged","scenario":"You flag that a department's late accruals delayed close, and the director fires back that finance's deadlines are 'unreasonable.' You need to answer the challenge without conceding a deadline that's actually standard.","task":"Write a 2-3 sentence reply that holds the deadline, explains why it exists, and offers real help.","tips":["Don't concede a reasonable deadline under pushback.","Explain the downstream cost of missing it — the delayed close.","Offer concrete help: a reminder, a template, a check-in."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-mid-20","level":"mid","profession":"finance","title":"The 'why didn't finance catch this' question","scenario":"A cost overrun surfaces and a leader asks, in the meeting, why finance didn't flag it sooner. Part of it is fair, part isn't — the data arrived late from the department. Answer without blame-shifting or false contrition.","task":"Write a 2-3 sentence reply that owns finance's part, states the fact about timing, and proposes a fix.","tips":["Own your genuine share cleanly.","State the timing fact without making it an accusation.","Propose the process fix so it's forward-looking."],"focus":["impact","precision"]},
    {"id":"pressure-fin-mid-21","level":"mid","profession":"finance","title":"The public request to bend the rules","scenario":"In front of others, a senior leader asks you to backdate an expense to hit this quarter's number. It's improper. You must decline clearly, in the room, without humiliating him or yourself.","task":"Write a 2-3 sentence reply that declines the improper ask plainly and offers the legitimate treatment.","tips":["Decline the improper action directly — no wiggle.","Frame it as policy, not personal judgment of him.","Offer the correct treatment so there's a way forward."],"focus":["impact","clarity"],"placeholder":"I can't backdate it — the expense belongs in the period it was incurred, and moving it wouldn't survive audit. Here's how we can handle it correctly:"},
    {"id":"pressure-fin-mid-22","level":"mid","profession":"finance","title":"The rapid-fire numbers quiz","scenario":"The CFO's office fires three questions at once: what's the overspend, what's driving it, and what are you doing about it. Under pressure you tend to blur them together. Answer each cleanly in order.","task":"Write a 3-sentence answer, one clean sentence per question, in the order asked.","tips":["Match the structure of the question — one answer per part.","Resist merging them into mush under time pressure.","Number them in your head: what, why, so-what."],"focus":["structure","clarity"]},
    {"id":"pressure-fin-mid-23","level":"mid","profession":"finance","title":"Challenged on an assumption","scenario":"Presenting the forecast, a director attacks your headcount assumption as 'too conservative.' It might be — or it might be right. Answer by making the assumption inspectable, not by defending your ego.","task":"Write a 2-3 sentence reply that surfaces the assumption, its basis, and invites a specific correction.","tips":["Make the assumption explicit and its source clear.","Invite the specific alternative — what number would he use?","Treat the challenge as a chance to pressure-test, not a fight."],"focus":["precision","impact"]},
    {"id":"pressure-fin-mid-24","level":"mid","profession":"finance","title":"The 'yes or no' on a genuinely uncertain call","scenario":"The CEO wants a yes/no on whether the cost-savings target is achievable, but the honest answer is 'probably, with conditions.' Forcing a bare yes would be dishonest; refusing to answer is unacceptable.","task":"Write a 2-3 sentence reply that gives a clear lean, the confidence, and the one condition.","tips":["Give a directional yes or no — don't hide in 'it depends.'","Attach your confidence honestly.","Name the single condition that decides it."],"focus":["impact","precision"],"placeholder":"Lean yes — I'd say 75% we hit it, and the one thing that decides it is whether the procurement renegotiation lands by Q3."},
    {"id":"pressure-fin-mid-25","level":"mid","profession":"finance","title":"The cold-call status in the elevator","scenario":"The CFO steps into the elevator with you: 'Where are we on cash for month-end?' You have twelve floors. There's one number, one risk, one action. Deliver it before the doors open.","task":"Write the spoken answer, under 20 seconds, leading with the number.","tips":["Number first — you have seconds, not minutes.","One risk, one action, then stop.","Practice it aloud so it fits the elevator, not the boardroom."],"focus":["concision","impact"],"placeholder":"Cash lands about $600K below plan at month-end — it's collections timing, and I'm chasing the two big accounts to close most of it this week."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-fin-mid-01","level":"mid","profession":"finance","title":"Making the case for the automation spend","scenario":"You want the CFO's office to approve $60K for an invoice-automation tool. Your draft is a flat list of features. To persuade, you need a before/after: what the team's month looks like now versus after.","task":"Write a 3-4 sentence pitch built on the contrast between the current state and the changed state.","tips":["Paint 'now': the hours lost, the errors, the late close.","Paint 'after': what those hours and errors become.","The gap between the two is the argument for the spend."],"focus":["impact","structure"],"placeholder":"Right now the team spends 20 hours a month keying invoices by hand, and that manual step causes most of our close delays. With the tool, that drops to near zero —"},
    {"id":"narrative-fin-mid-02","level":"mid","profession":"finance","title":"Concrete stakes for the cost-control push","scenario":"You're asking department heads to take a cost-discipline effort seriously, but 'we need to manage costs carefully' washes over them. Make the stakes concrete: what a lost quarter of discipline actually costs the company.","task":"Write a 2-3 sentence appeal that makes the abstract stakes tangible and specific.","tips":["Turn 'manage costs' into a number and a consequence.","Tie the discipline to something they care about — headcount, bonuses, the year.","Concrete stakes move people; abstractions don't."],"focus":["impact","precision"],"placeholder":"Every month we let costs drift 2% is $400K — that's the difference between funding next year's hiring plan and freezing it."},
    {"id":"narrative-fin-mid-03","level":"mid","profession":"finance","title":"Pre-empting the objection to the freeze","scenario":"You're announcing a hiring pause and you know the first objection: 'but my team is drowning.' If you don't address it up front, the announcement gets buried in pushback.","task":"Write a 3-4 sentence message that names and answers the strongest objection before it's raised.","tips":["Name the objection out loud — it disarms it.","Answer it honestly: the exception path for critical roles.","Pre-empting shows respect and controls the narrative."],"focus":["impact","audience"]},
    {"id":"narrative-fin-mid-04","level":"mid","profession":"finance","title":"Selling the re-forecast as opportunity","scenario":"The re-forecast shows a shortfall, and you could present it as pure bad news. But the reframe is real: knowing now, with two quarters left, means the company can still act. Frame the change that's possible.","task":"Write a 2-3 sentence framing that turns the shortfall into a call to act, not just a loss.","tips":["Don't sugarcoat, but don't leave them only with the loss.","The narrative: we see it early, so we can still move.","End on the change that's still available."],"focus":["impact","structure"],"placeholder":"We're tracking $2M short — but we're seeing it in July, not December, which means there's still time to close most of it if we act now."},
    {"id":"narrative-fin-mid-05","level":"mid","profession":"finance","title":"The capex story for the committee","scenario":"You're recommending a $500K warehouse investment to the approval committee. The numbers work, but committees fund stories, not spreadsheets. Build the narrative: the problem the equipment solves and what changes.","task":"Write a 3-4 sentence pitch that tells the problem-to-solution story with the payback woven in.","tips":["Start with the pain the current equipment causes — vividly, factually.","Show the after-state the investment buys.","Weave the payback in as proof, not as the whole pitch."],"focus":["impact","structure"]},
    {"id":"narrative-fin-mid-06","level":"mid","profession":"finance","title":"Persuading a department head to defer","scenario":"You need the sales director to voluntarily defer two hires to Q3 to hold the budget. Ordering him won't stick; persuading him will. Frame it around what deferring protects for his team.","task":"Write a 2-3 sentence persuasion that frames the deferral as serving his interest, not just finance's.","tips":["Find the version where deferring helps him: it protects his travel and tools budget.","Make it a choice he'd defend, not one imposed on him.","Persuasion that lasts aligns with the other person's stake."],"focus":["audience","impact"]},
    {"id":"narrative-fin-mid-07","level":"mid","profession":"finance","title":"The savings win worth telling","scenario":"Your team's process change saved the company $200K this year, and you want the CFO's office to notice and back the next phase. A dry number won't land; the story of what changed will.","task":"Write a 3-sentence narrative of the win: the problem, the change, the result.","tips":["Problem, change, result — the shape of every good win story.","Make the $200K the payoff of a story, not a bare stat.","Point forward: the next phase this success justifies."],"focus":["impact","structure"],"placeholder":"Six months ago we were double-handling every intercompany invoice, costing days each month. We rebuilt the process, and the result is $200K saved this year — with more available if we extend it to the next region."},
    {"id":"narrative-fin-mid-08","level":"mid","profession":"finance","title":"Framing the audit finding as improvement","scenario":"The audit turned up a control gap in procurement, and you need to present the fix to the CFO's office without it reading as pure failure. Frame it as the before/after of a strengthened control.","task":"Write a 2-3 sentence framing that acknowledges the gap and centers the improvement.","tips":["Acknowledge the gap plainly — don't spin it away.","Center the narrative on the stronger control now in place.","End with the state you've moved to, not the one you're leaving."],"focus":["impact","structure"]},
    {"id":"narrative-fin-mid-09","level":"mid","profession":"finance","title":"The objection you must pre-empt on cost allocation","scenario":"You're rolling out a new cost-allocation method that will raise some departments' shared costs. The loudest objection will be 'you're just dumping costs on us.' Address it before the numbers hit inboxes.","task":"Write a 3-4 sentence rollout that pre-empts the 'dumping' objection with the fairness logic.","tips":["Name the fear: this looks like cost-dumping.","Answer with the principle: costs follow usage, which is fairer than before.","Pre-empting the objection keeps the rollout from becoming a fight."],"focus":["audience","impact"]},
    {"id":"narrative-fin-mid-10","level":"mid","profession":"finance","title":"Making cash discipline vivid for leadership","scenario":"You want the leadership team to prioritize collecting from two slow-paying customers. 'Improve working capital' means nothing to them. Make the stakes concrete: what that cash could do if freed.","task":"Write a 2-3 sentence appeal that connects the slow payments to something leadership cares about.","tips":["Translate 'working capital' into a number and a use.","The freed cash funds something specific — name it.","Concrete beats abstract every time you want action."],"focus":["impact","audience"],"placeholder":"Two customers are sitting on $400K of our cash by paying 20 days late — that $400K is exactly what we need to fund the Q4 hires without touching the credit line."},
    {"id":"narrative-fin-mid-11","level":"mid","profession":"finance","title":"The change-story for the new forecast model","scenario":"You're rolling out a driver-based forecast model to skeptical department heads. They'll resist change. Frame the before/after: how forecasting felt before (numbers that moved for no reason) versus after (numbers tied to their drivers).","task":"Write a 3-4 sentence pitch built on the contrast, aimed at winning their buy-in.","tips":["Before: forecasts that changed opaquely, frustrating everyone.","After: numbers that move only when their real drivers move.","Sell the benefit to them, not the elegance to you."],"focus":["audience","impact"]},
    {"id":"narrative-fin-mid-12","level":"mid","profession":"finance","title":"Persuading the CFO to hold contingency","scenario":"Two departments want the $250K contingency and you think it should be held. To persuade the CFO's office, you need a narrative of risk, not just a preference. Make the downside vivid enough to justify caution.","task":"Write a 2-3 sentence persuasion that makes the case for holding by making the risk concrete.","tips":["Show the scenario where releasing it now hurts.","Make the downside specific: the renewal that could slip and the gap it leaves.","Frame holding as prudent optionality, not hoarding."],"focus":["impact","precision"]},
    {"id":"narrative-fin-mid-13","level":"mid","profession":"finance","title":"The pitch to standardize spend approvals","scenario":"You want to introduce a $10K approval threshold across departments, and heads will see it as bureaucracy. Persuade by showing the current chaos and the calmer state a threshold creates.","task":"Write a 3-4 sentence pitch that contrasts the messy present with the cleaner future the rule buys.","tips":["Name the current pain: surprise costs, no visibility, audit flags.","Show the after: predictable, defensible, faster where it's small.","Frame the rule as protection, not red tape."],"focus":["impact","audience"]},
    {"id":"narrative-fin-mid-14","level":"mid","profession":"finance","title":"Concrete stakes for on-time accruals","scenario":"Department heads treat the accrual deadline as optional. 'It delays close' is too abstract. Make the stakes real: whose Monday gets ruined, what leadership decision gets delayed, when their own numbers go wrong.","task":"Write a 2-3 sentence appeal that makes the cost of a late accrual concrete and personal.","tips":["Show what a late accrual actually breaks downstream.","Make it personal: their own numbers look wrong when they're late.","Abstract deadlines get missed; concrete consequences get met."],"focus":["impact","audience"]},
    {"id":"narrative-fin-mid-15","level":"mid","profession":"finance","title":"Selling the analyst investment upward","scenario":"You want to hire an additional analyst and need to persuade the CFO's office. The dry version — 'the team is stretched' — won't win a headcount in a freeze. Build the before/after of what the role unlocks.","task":"Write a 3-4 sentence business case built on what changes when the role is filled.","tips":["Before: what falls through the cracks with the current team.","After: the analysis and speed the added role buys.","Tie it to a decision the CFO's office cares about improving."],"focus":["impact","structure"]},
    {"id":"narrative-fin-mid-16","level":"mid","profession":"finance","title":"Pre-empting 'finance is being difficult'","scenario":"You're about to decline several spend requests, and the narrative in the halls will be 'finance is blocking everything.' Get ahead of it: frame the declines as protecting the shared budget everyone draws on.","task":"Write a 2-3 sentence framing that pre-empts the 'finance is difficult' story.","tips":["Name the story you're pre-empting.","Reframe: the declines protect the pool that funds their priorities.","Show you're on their side of the outcome, not just the gatekeeper."],"focus":["audience","impact"]},
    {"id":"narrative-fin-mid-17","level":"mid","profession":"finance","title":"The turnaround story for the CFO","scenario":"A department that was badly over budget is now back on track after your intervention, and you want the CFO's office to see the arc. A single 'we're on plan now' misses the story worth telling.","task":"Write a 3-sentence narrative: where it was, what you did, where it is now.","tips":["Establish the starting trouble honestly.","Name the specific intervention that turned it.","Land on the current state as the payoff."],"focus":["impact","structure"],"placeholder":"In Q1 this department was tracking $300K over and climbing. We restructured its contractor spend and put a $20K approval gate in place, and it's now back on plan for the year."},
    {"id":"narrative-fin-mid-18","level":"mid","profession":"finance","title":"Persuading against the popular capital project","scenario":"A charismatic business-unit lead has the room excited about a $2M project, and you need to persuade the committee it doesn't pay back. You're the wet blanket unless you build a better story.","task":"Write a 2-3 sentence persuasion that respects the excitement but reframes around the payback reality.","tips":["Acknowledge what's genuinely appealing about it.","Reframe on the number that matters: a seven-year payback.","Offer the alternative that does pay back, so you're not just against."],"focus":["impact","precision"]},
    {"id":"narrative-fin-mid-19","level":"mid","profession":"finance","title":"The stakes of the auto-renewal","scenario":"You want the IT director to actually act on a contract auto-renewing at +18%. A neutral heads-up gets ignored. Make the stakes vivid: what the increase costs over the contract life if he does nothing.","task":"Write a 2-3 sentence message that makes the cost of inaction concrete and time-bound.","tips":["Quantify the cost of doing nothing over the full term.","Attach the deadline that makes it urgent.","Concrete cost plus a clock drives action; a soft heads-up doesn't."],"focus":["impact","precision"],"placeholder":"If we let this renew, the 18% bump adds $54K a year — $162K over the three-year term — and the window to renegotiate closes on the 15th."},
    {"id":"narrative-fin-mid-20","level":"mid","profession":"finance","title":"Reframing the budget cut as a choice","scenario":"You must tell a department its budget is being cut 8%, and 'your budget is cut' invites resentment and paralysis. Reframe it as a choice about what to protect, giving them agency inside the constraint.","task":"Write a 3-sentence message that frames the cut as a prioritization decision they get to shape.","tips":["Acknowledge the cut plainly.","Reframe: within it, they choose what to protect.","Agency inside a constraint turns resentment into engagement."],"focus":["audience","impact"]},
    {"id":"narrative-fin-mid-21","level":"mid","profession":"finance","title":"The persuasive one-pager for shared savings","scenario":"You've found a way to save $150K by consolidating two vendors, but it requires two departments to give up their preferred supplier. You need a one-pager that persuades both to cooperate.","task":"Write the 3-4 sentence core of the one-pager: the shared prize, the ask, the pre-empted objection.","tips":["Lead with the shared win, not the individual sacrifice.","State the specific ask of each department.","Pre-empt the 'but I like my vendor' objection with the trade-off math."],"focus":["impact","audience"]},
    {"id":"narrative-fin-mid-22","level":"mid","profession":"finance","title":"Making the risk register persuasive, not just complete","scenario":"Your budget risk register is thorough but inert — the CFO's office reads it and does nothing. To provoke action on the top risk, you need to tell its story: the trigger, the impact, the window to prevent it.","task":"Write a 2-3 sentence narrative of the top risk that would actually prompt a decision.","tips":["A list informs; a story about the top risk persuades.","Trigger, impact, and the closing window — in that order.","End with the specific decision that would defuse it."],"focus":["impact","structure"]},
    {"id":"narrative-fin-mid-23","level":"mid","profession":"finance","title":"The before/after for closing faster","scenario":"You want leadership to back a project to shorten month-end close from eight days to four. Sell the change by contrasting the current cost of a slow close with the decisions a fast close enables.","task":"Write a 3-4 sentence pitch built on the contrast between the slow present and the fast future.","tips":["Now: leadership decides on eight-day-old numbers.","After: they act on fresh data, four days sooner.","The value isn't speed for its own sake — it's better, faster decisions."],"focus":["impact","structure"]},
    {"id":"narrative-fin-mid-24","level":"mid","profession":"finance","title":"Pre-empting the CFO's toughest question","scenario":"You're recommending the company draw on its contingency, and you know the CFO's hardest question will be 'what if we need it later?' Build that answer into the pitch so it doesn't derail you.","task":"Write a 2-3 sentence recommendation that pre-empts the 'what if we need it later' objection.","tips":["State your recommendation, then immediately field the hardest question.","Answer 'what if later' with the specific backstop you've identified.","Pre-empting the killer objection is what separates a pitch from a wish."],"focus":["impact","structure"],"placeholder":"I recommend drawing $150K of the contingency now. If we need it again later, the December collections give us the same cushion back — so this isn't spending it, it's timing it."},
    {"id":"narrative-fin-mid-25","level":"mid","profession":"finance","title":"The spoken pitch for the process change","scenario":"You have two minutes at the leadership meeting to win support for standardizing spend reporting. Read aloud, a feature list falls flat. You need a spoken narrative: the frustration everyone shares, then the relief the change brings.","task":"Write the 2-minute spoken pitch: the shared pain, the change, the payoff — said aloud.","tips":["Open on a frustration the room already feels.","Introduce the change as the relief to that shared pain.","Land on the concrete payoff — and make it sound good aloud."],"focus":["impact","structure"],"placeholder":"You all know the feeling — you ask three departments for their spend and get three different formats, three different numbers, and a week of reconciliation. Here's what changes:"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-fin-mid-01","level":"mid","profession":"finance","title":"The budget cut nobody wants","scenario":"You have to tell the engineering director his department's budget is being cut 10% mid-year. Your draft opens with three paragraphs of economic context before the number. Clear is kind: he deserves the news first.","task":"Write a 2-3 sentence message that front-loads the cut, then the one reason.","tips":["Lead with the cut and the number — burying it is unkind.","One clear reason, not a wall of context.","Then the path: what you'll help him protect."],"focus":["clarity","impact"],"placeholder":"Your budget is being cut 10% for the rest of the year — about $400K. The reason is the company-wide revenue shortfall, and I want to work with you on what to protect."},
    {"id":"hard-fin-mid-02","level":"mid","profession":"finance","title":"The clean 'no' to the pet project","scenario":"A director has championed a $80K initiative for months and you have to decline it. Your draft is full of 'unfortunately' and 'I wish I could,' which reads as a soft maybe. Give a clean no.","task":"Write a 2-3 sentence decline that is unambiguous, respectful, and reason-backed.","tips":["'No' should be findable in one read — don't drown it.","Cut the 'I wish I could' theater; state the real reason.","Respect is in the clarity, not the cushioning."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-03","level":"mid","profession":"finance","title":"Behavior, impact, ask to the analyst","scenario":"Your analyst has sent two reports with numbers that didn't tie out, and it's damaging finance's credibility. You need to give feedback that changes the behavior without crushing them.","task":"Write a 3-sentence feedback message using behavior, impact, then the ask.","tips":["Behavior: name the specific thing — two reports with untied numbers.","Impact: what it cost — credibility with the CFO's office.","Ask: the concrete change — a reconciliation check before sending."],"focus":["clarity","structure"],"placeholder":"The last two reports went out with numbers that didn't reconcile. When that happens, the CFO's office starts doubting all our figures, not just those two. Before anything goes out, I need a tie-out check —"},
    {"id":"hard-fin-mid-04","level":"mid","profession":"finance","title":"Telling the CFO the forecast is worse","scenario":"You have to tell the CFO's office that the outlook has deteriorated further — another $500K of downside since last week. The temptation is to bury it in caveats. They need it straight and early.","task":"Write a 2-3 sentence message that delivers the worse news up front, cleanly.","tips":["Bad news first — the CFO's office plans on it.","State the new number and what changed since last week.","No caveats stacked in front of the headline."],"focus":["clarity","impact"],"placeholder":"The outlook has worsened by another $500K since last week — a second enterprise deal now looks likely to slip to next year."},
    {"id":"hard-fin-mid-05","level":"mid","profession":"finance","title":"The overspend conversation with a peer","scenario":"A peer department head is consistently overspending and dismissive when you raise it. You need to have a direct conversation that names the pattern without turning it into a personal fight.","task":"Write a 2-3 sentence opener for the conversation that names the pattern and its consequence plainly.","tips":["Name the pattern factually, not accusingly.","State the consequence: it's now an audit and budget risk.","Invite a fix, but don't soften the reality away."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-06","level":"mid","profession":"finance","title":"Declining the senior leader's exception","scenario":"A senior VP wants you to approve an over-policy expense as a one-time favor. It's not defensible. You have to decline someone above you clearly, without either capitulating or being combative.","task":"Write a 2-3 sentence decline that holds the line, explains it, and offers a legitimate route.","tips":["Decline plainly — seniority doesn't change the policy.","Anchor it to the rule and the audit, not to your opinion of him.","Offer the legitimate path so it's a redirect, not a wall."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-07","level":"mid","profession":"finance","title":"The audit finding the team won't like","scenario":"You have to tell the procurement team the audit found they've been approving invoices without purchase orders — a control failure. They'll be defensive. Clear is kind: state it plainly, then move to the fix.","task":"Write a 3-sentence message that states the finding, its stakes, and the required change without blame.","tips":["State the finding as a fact, not an accusation.","Stakes: it's a control finding the auditors will track.","Move fast to the fix and who owns it — that's the point."],"focus":["clarity","structure"]},
    {"id":"hard-fin-mid-08","level":"mid","profession":"finance","title":"Telling a director their pet metric is going away","scenario":"A director loves a report you produce that no longer serves anyone else, and you're discontinuing it to free your team's time. He'll take it personally. Deliver the decision kindly but firmly.","task":"Write a 2-3 sentence message that ends the report clearly and offers what remains available.","tips":["State the decision plainly — the report is being discontinued.","Give the honest reason: it's used by one person now.","Offer the alternative so he isn't left empty-handed."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-09","level":"mid","profession":"finance","title":"The freeze on an approved hire","scenario":"A hire the sales director already got approved is being frozen because the company situation changed. This is a broken promise from his view. You have to deliver it honestly, owning the reversal.","task":"Write a 3-sentence message that delivers the freeze, acknowledges the reversal, and gives the path.","tips":["Front-load the hard news: the approved hire is on hold.","Acknowledge that this reverses a commitment — don't pretend it doesn't.","Give the exception path or the timeline so it's not a dead end."],"focus":["clarity","impact"],"placeholder":"I have to reverse something we'd approved: the senior analyst hire is frozen under the new company-wide pause. I know that's a commitment being pulled back, and here's the exception route if the role is critical:"},
    {"id":"hard-fin-mid-10","level":"mid","profession":"finance","title":"Feedback to a defensive department head","scenario":"A department head keeps missing accrual deadlines and blames finance's system every time. You need to deliver feedback that gets past the deflection to the real behavior and its impact.","task":"Write a 3-sentence message using behavior, impact, ask, that doesn't get pulled into the system argument.","tips":["Name the behavior: accruals late three quarters running.","Impact: it delays close for everyone, not just his team.","Ask: a specific commitment, and offer to help with the mechanics."],"focus":["clarity","structure"]},
    {"id":"hard-fin-mid-11","level":"mid","profession":"finance","title":"The duplicate-payment admission","scenario":"Your team made an error — a $28K duplicate payment — and you have to tell the controller before he finds it. Owning a mistake up the chain is hard. Clear and early beats discovered and late.","task":"Write a 2-3 sentence message that owns the error, states the recovery status, and the prevention.","tips":["Own it in the first sentence — no burying the lede.","State where recovery stands so it's news plus resolution.","Name the control change so it doesn't recur."],"focus":["clarity","impact"],"placeholder":"I need to flag an error on our side: we double-paid a $28K vendor invoice. The vendor's confirmed and the refund lands within ten days, and we've added a duplicate-check to the payment run."},
    {"id":"hard-fin-mid-12","level":"mid","profession":"finance","title":"Cutting the contractor the manager relies on","scenario":"Budget pressure means a contractor a manager depends on can't be renewed. The manager will be upset and short-staffed. Deliver the news directly, with the reason and what you can offer instead.","task":"Write a 2-3 sentence message that delivers the non-renewal clearly and offers what help exists.","tips":["State the non-renewal and the date plainly.","Give the budget reason without over-apologizing.","Offer the real alternative — reprioritization, a smaller scope — honestly."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-13","level":"mid","profession":"finance","title":"The 'no' to a well-liked colleague","scenario":"A colleague you like personally asks you to expedite a payment outside the normal run for a vendor they favor. It's not urgent enough to justify breaking the process. The relationship makes the no harder.","task":"Write a 2-3 sentence decline that's warm but firm and explains the standard.","tips":["Warmth doesn't require a soft or hidden no.","Explain the standard so it's not personal.","Offer the normal timeline as the answer, clearly."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-14","level":"mid","profession":"finance","title":"Delivering a poor performance message to your own report","scenario":"Your junior analyst's work quality has slipped and you have to raise it in a one-on-one. Vague reassurance won't help them; blunt criticism will crush them. Behavior, impact, ask keeps it fair.","task":"Write a 3-4 sentence message that names the specific slip, its impact, and a concrete path to improve.","tips":["Specific behavior, not 'your work has been off.'","Impact stated plainly, without exaggeration.","A concrete, achievable ask — and your support behind it."],"focus":["clarity","structure"]},
    {"id":"hard-fin-mid-15","level":"mid","profession":"finance","title":"Telling leadership the target is unreachable","scenario":"The cost-savings target leadership set is, in your honest assessment, unreachable this year. They don't want to hear it. Delivering the hard truth now beats letting them plan on a fantasy.","task":"Write a 2-3 sentence message that states the target is out of reach, with the reason and the realistic figure.","tips":["Say it plainly: the target won't be met.","Give the reason and the number that is achievable.","Offer the honest revised target, not just the bad news."],"focus":["clarity","impact"],"placeholder":"I don't think we can hit the $1.5M target this year — realistically it's about $1.1M. Two of the initiatives we counted on won't land until next year, and here's what's still in reach:"},
    {"id":"hard-fin-mid-16","level":"mid","profession":"finance","title":"The escalation to the CFO about a peer","scenario":"A peer department head is bypassing spend controls and won't stop despite your warnings. You have to escalate to the CFO's office — naming a colleague. Deliver it factually, without personal attack.","task":"Write a 2-3 sentence escalation that states the pattern, the risk, and your recommended action.","tips":["Facts and pattern, not character judgment.","State the audit/control risk clearly.","Recommend a specific action so it's constructive escalation."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-17","level":"mid","profession":"finance","title":"Withdrawing a number you gave in error","scenario":"You told a director last week she had $50K of budget room, but you'd double-counted; she actually has $15K. She may have already committed against the wrong number. You have to correct it fast and own it.","task":"Write a 2-3 sentence correction that owns the error, gives the right number, and checks the exposure.","tips":["Own the mistake immediately — you gave a wrong number.","State the correct figure clearly.","Check what she's committed against it so you can help contain it."],"focus":["clarity","precision"],"placeholder":"I have to correct a number I gave you: your available budget is $15K, not $50K — I double-counted a committed contract. Have you committed anything against the $50K yet, so we can sort it out?"},
    {"id":"hard-fin-mid-18","level":"mid","profession":"finance","title":"The uncomfortable audit-cooperation ask","scenario":"The HR director is stonewalling the auditors' request for payroll records, treating it as an intrusion. You have to tell her cooperation isn't optional, without making her more defensive.","task":"Write a 2-3 sentence message that makes the requirement clear while respecting her concern.","tips":["State plainly that the request must be met — it's not optional.","Acknowledge the concern without conceding the point.","Give the specific, bounded thing needed and the deadline."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-19","level":"mid","profession":"finance","title":"Declining your boss's informal ask","scenario":"Your controller casually asks you to 'find room' to move a cost into next quarter to smooth this quarter's numbers. It's a soft nudge toward something improper. You have to decline upward, tactfully but clearly.","task":"Write a 2-3 sentence reply that declines the improper timing and explains the constraint.","tips":["Decline the specific improper action, not the relationship.","Anchor to the accounting reality: the cost belongs in this period.","Offer legitimate levers if there are any, so you're helping."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-20","level":"mid","profession":"finance","title":"Delivering the layoff-cost reality","scenario":"Leadership is weighing a restructuring and asks you to present the severance and one-time costs, which are large and unwelcome. You have to deliver hard numbers to a room that hoped they'd be smaller.","task":"Write a 2-3 sentence delivery that states the costs plainly without softening them into meaninglessness.","tips":["Give the real numbers — softening them helps no one decide.","State the one-time cost and the ongoing saving separately.","Deliver it steadily; the room needs the truth to decide."],"focus":["clarity","precision"]},
    {"id":"hard-fin-mid-21","level":"mid","profession":"finance","title":"The 'your project is over budget and it's your call' message","scenario":"A project manager's initiative is $60K over and needs either more money or a scope cut — and it's her decision, but she must know the reality first. Deliver the hard fact, then hand her the choice.","task":"Write a 2-3 sentence message that states the overrun plainly and frames the decision as hers.","tips":["State the overrun and the number without hedging.","Make the two options clear and concrete.","Hand her the decision — that's respect, not abdication."],"focus":["clarity","structure"],"placeholder":"Your project is $60K over budget as of this week. You have two real options — add $60K from your discretionary line, or cut the final phase — and it's your call which."},
    {"id":"hard-fin-mid-22","level":"mid","profession":"finance","title":"Correcting a leader's public misstatement","scenario":"In a meeting, a leader confidently states a budget figure that's wrong in a way that will misdirect the discussion. You have to correct it in the room, without embarrassing him.","task":"Write a 2-sentence correction you'd say aloud that fixes the number gracefully.","tips":["Correct the fact, not the person.","Offer the right number as an addition, not a rebuttal.","Keep it brief so the meeting moves on, corrected."],"focus":["clarity","precision"]},
    {"id":"hard-fin-mid-23","level":"mid","profession":"finance","title":"Telling a department its request is permanently declined","scenario":"A department has re-submitted the same $120K request three quarters running, and the answer will keep being no. You need to deliver a definitive decline so they stop resubmitting and can plan around it.","task":"Write a 2-3 sentence message that makes the no final and clear, with the reason it won't change.","tips":["Make it definitive — a soft no invites a fourth request.","Give the structural reason it won't change.","Redirect their energy to what is possible instead."],"focus":["clarity","impact"]},
    {"id":"hard-fin-mid-24","level":"mid","profession":"finance","title":"Owning a reporting error to department heads","scenario":"A dashboard bug overstated several departments' remaining budgets for two weeks, and some may have overcommitted. You have to send the correction to all affected heads, owning it without triggering panic.","task":"Write a 3-sentence message that owns the error, states the correct position, and gives the next step.","tips":["Own the error in plain terms up front.","Tell each head how to find their correct number.","Give a next step for anyone who overcommitted — no blame."],"focus":["clarity","structure"]},
    {"id":"hard-fin-mid-25","level":"mid","profession":"finance","title":"The spoken bad-news update to the CFO","scenario":"You have to tell the CFO, in person, that month-end cash will miss plan by $600K. Said aloud, there's a temptation to bury it in the middle of a longer update. Lead with it, own it, offer the plan.","task":"Write the spoken 3-sentence delivery: the miss first, the cause, the action.","tips":["Lead aloud with the number — don't warm up to it.","One clear cause, stated evenly.","End on the action, so you're delivering a plan, not just a problem."],"focus":["clarity","impact"],"placeholder":"Cash will miss plan by about $600K at month-end. It's collections timing — two large accounts slipped past their terms — and I'm personally chasing both to recover most of it this week."}
  ],
  "putting-it-together": [
    {"id":"together-fin-mid-01","level":"mid","profession":"finance","title":"The full budget-review open","scenario":"You're opening the quarterly budget review with the operations director: the department is 12% over, you want a decision between slowing hiring and cutting contractors, and you have 30 minutes. This needs BLUF, structure, and a clear ask all at once.","task":"Write the 3-4 sentence open that leads with the point, frames the decision, and signposts the meeting.","tips":["Lead with the trend and the decision the meeting exists to make.","Signpost the shape: here's what we'll cover, here's what we decide.","Everything you've practiced — point, structure, ask — in one open."],"focus":["structure","impact"],"placeholder":"You're 12% over budget for the year, and I want us to leave today with a decision between two levers. I'll show you the drivers first, then the two options, and we'll pick one in the last ten minutes."},
    {"id":"together-fin-mid-02","level":"mid","profession":"finance","title":"The CFO memo, end to end","scenario":"You're writing the mid-year re-forecast memo to the CFO's office: revenue 4% light, two drivers, a recommendation to hold contingency. It must lead with the point, be precise, own a recommendation, and fit one page.","task":"Write the memo's opening paragraph (3-4 sentences) integrating BLUF, precision, and a clear recommendation.","tips":["Headline the 4% miss in sentence one, with the number.","Two drivers, quantified, not vaguely gestured at.","Close the paragraph with your recommendation, owned."],"focus":["structure","precision"],"placeholder":"The re-forecast shows full-year revenue 4% below plan — about $2M — driven mainly by two enterprise deals slipping to next year. Given that, I recommend holding the $250K contingency until Q4."},
    {"id":"together-fin-mid-03","level":"mid","profession":"finance","title":"Matching register to the channel","scenario":"The same message — the department is $80K over and needs to slow spending — could go as a formal memo, a Slack ping, or a hallway word. You're sending it on Slack to a busy director. Match the register to the channel.","task":"Write the Slack version: right length, right tone, right level of detail for the channel.","tips":["Slack rewards brevity and directness over formality.","Lead with the number and the ask; skip the memo scaffolding.","Match the reader's channel habits, not your document instincts."],"focus":["audience","concision"],"placeholder":"Heads up — you're $80K over for the year and climbing. Can we grab 15 min this week to pick what to slow before it gets harder?"},
    {"id":"together-fin-mid-04","level":"mid","profession":"finance","title":"Editing your own draft like a reader","scenario":"You've drafted a dense variance email to the sales director. Before sending, you need to read it as he will — busy, skimming, non-finance — and cut what won't survive that read.","task":"Write the 2-3 sentence edited version that survives a busy non-finance skim.","tips":["Read it as the recipient, not the author.","Cut jargon and any sentence he'd skip.","Keep only what he needs to act — number, cause, ask."],"focus":["audience","concision"]},
    {"id":"together-fin-mid-05","level":"mid","profession":"finance","title":"The board-pack summary paragraph","scenario":"You're writing the finance summary for the board pack: on track for the year, one risk, no action needed from the board yet. It must be precise, high-altitude, and reassuring without being complacent.","task":"Write the 3-4 sentence board summary integrating altitude, precision, and a clear risk flag.","tips":["Board altitude: the year's verdict, not the monthly detail.","Precise on the one risk — size and trigger.","State plainly whether the board needs to do anything."],"focus":["audience","precision"],"placeholder":"Finance is on track for the full year, with revenue and costs both within 1% of plan. The one risk to flag is the two enterprise renewals in Q4, worth $3M combined; no board action is needed yet."},
    {"id":"together-fin-mid-06","level":"mid","profession":"finance","title":"The spend decision under real constraints","scenario":"Three departments want the last $150K of flexible budget, you can fund one, and you must communicate the decision to all three in a way that's clear, defensible, and doesn't poison relationships.","task":"Write the 3-4 sentence message to all three that states the decision, the basis, and respects the two who lost.","tips":["State who got it and why — transparent basis defuses resentment.","Be clear and final, not mushy, with the two declined.","Leave the relationships intact: acknowledge their cases fairly."],"focus":["impact","audience"]},
    {"id":"together-fin-mid-07","level":"mid","profession":"finance","title":"The re-forecast presentation, live","scenario":"You have ten minutes to present the re-forecast to the leadership team: the miss, the drivers, the levers, the recommendation. It must be structured, own a call, and handle the pushback you'll get.","task":"Write the 4-5 sentence spoken open that leads, structures, and states your recommendation before questions.","tips":["Lead with the bottom line, then the shape of the ten minutes.","Own the recommendation before they can force a menu.","Pre-empt the obvious pushback in your framing."],"focus":["structure","impact"]},
    {"id":"together-fin-mid-08","level":"mid","profession":"finance","title":"The hard 'no' that keeps the relationship","scenario":"You're declining a valued director's $100K request permanently, and you want the decline to be clear, kind, and to preserve a partnership you'll need for years. Front-load the no, but land the relationship.","task":"Write a 3-sentence message that delivers a clean no and protects the working relationship.","tips":["Clear is kind — the no comes first, unmistakable.","One honest reason, no theater.","Close on the partnership and what you can do together instead."],"focus":["clarity","audience"]},
    {"id":"together-fin-mid-09","level":"mid","profession":"finance","title":"The audit-status update to the controller","scenario":"You're updating the controller on audit prep: mostly on track, one blocker (procurement docs), your recommendation to escalate. It needs BLUF, clean structure, and a clear ask, in a short message.","task":"Write the 3-sentence update that leads with status, isolates the blocker, and makes the ask.","tips":["Status headline first: on track except one thing.","Isolate the blocker so it can't hide.","Make the ask explicit — what you need him to do."],"focus":["structure","clarity"],"placeholder":"Audit prep is on track except for one blocker: procurement still hasn't produced three signed contracts due to the auditors Friday. I'd like you to escalate directly to the procurement lead today so we don't slip the timeline."},
    {"id":"together-fin-mid-10","level":"mid","profession":"finance","title":"Explaining a complex number simply, in writing","scenario":"The customer-success director's costs jumped due to a reallocation, an accrual, and a timing shift all at once. You must explain it to her clearly, in her language, precisely, and briefly — all four skills together.","task":"Write the 3-4 sentence explanation that's plain, precise, structured, and short.","tips":["Structure the three causes cleanly, largest first.","Translate each into plain terms and a number.","Keep it short enough that she actually reads all of it."],"focus":["audience","precision"]},
    {"id":"together-fin-mid-11","level":"mid","profession":"finance","title":"The elevator answer that does everything","scenario":"The CFO asks in the elevator how the year looks. You have 30 seconds to lead with the verdict, give the one risk, own a view, and sound composed — everything at once.","task":"Write the 30-second spoken answer integrating BLUF, one risk, and a confident view.","tips":["Verdict first, then the single risk.","Own a confidence level — don't hedge into mush.","Compose it to sound calm and complete in half a minute."],"focus":["impact","concision"],"placeholder":"On track for the year — revenue and costs both within 1% of plan. The one thing I'm watching is the two Q4 renewals, and my read is we hit the number as long as one of the two lands."},
    {"id":"together-fin-mid-12","level":"mid","profession":"finance","title":"The decision paper that leads and structures","scenario":"You're writing a one-page decision paper for the CFO's office on closing a $200K gap: three options, your recommendation, the risk of each. It must lead with the recommendation, structure the options in parallel, and be precise.","task":"Write the paper's opening (3-4 sentences): recommendation first, then the structured options preview.","tips":["Recommendation on line one — don't make them find it on page two.","Preview the three options in parallel form.","Precise on the number and the trade-offs."],"focus":["structure","impact"]},
    {"id":"together-fin-mid-13","level":"mid","profession":"finance","title":"The feedback that changes behavior and keeps trust","scenario":"Your analyst is technically strong but buries the point in every memo. You want to give feedback that fixes the habit, respects their skill, and integrates the structure and audience lessons you'd want them to internalize.","task":"Write a 3-4 sentence feedback message that names the pattern, its cost, the fix, and the respect.","tips":["Behavior, impact, ask — the tested shape.","Fix framed as a reusable habit: point first, detail after.","Acknowledge the strength so the feedback lands, not wounds."],"focus":["structure","audience"]},
    {"id":"together-fin-mid-14","level":"mid","profession":"finance","title":"The one message, three stakeholders","scenario":"A cost overrun needs communicating up to the CFO's office, across to the affected department head, and down to your analyst — same facts, three registers. You're writing the CFO's-office version first.","task":"Write the 2-3 sentence CFO's-office version, calibrated to that audience's altitude and needs.","tips":["Pick the one audience and write only for them here.","CFO altitude: the size, the year impact, the action.","Resist blending in the department-head or analyst framing."],"focus":["audience","concision"]},
    {"id":"together-fin-mid-15","level":"mid","profession":"finance","title":"The recovery message after your miss","scenario":"Your forecast missed and you have to rebuild credibility with the CFO's office. The message must own the miss, explain the fix, and re-establish confidence — clarity, precision, and presence together.","task":"Write a 3-4 sentence message that owns the miss, names the fix precisely, and re-establishes your credibility.","tips":["Own it cleanly — no defensiveness.","Name the specific process change, with the mechanism.","Close with quiet confidence, not over-promising."],"focus":["impact","precision"],"placeholder":"The Q2 miss was $340K, almost all one slipped deal. I've changed the forecast to separate committed from at-risk pipeline, so a single slip can't surprise us like that again — and you'll see the split in this quarter's pack."},
    {"id":"together-fin-mid-16","level":"mid","profession":"finance","title":"The town-hall finance minute","scenario":"You have 60 seconds at the all-hands to give a finance update to general staff: one message, plain language, memorable, honest. Everything about audience, concision, and structure applies.","task":"Write the 60-second spoken update: one governing message, plainly, that staff can repeat.","tips":["One message people remember at lunch — pick it.","Zero jargon; general-staff language throughout.","Structure it so the point lands first and last."],"focus":["audience","concision"]},
    {"id":"together-fin-mid-17","level":"mid","profession":"finance","title":"The escalation to the CFO, complete","scenario":"You're escalating a serious budget risk — a possible $500K shortfall — to the CFO's office. It needs to lead with the risk, be precise about the trigger and size, own a recommendation, and propose the action.","task":"Write the 3-4 sentence escalation integrating BLUF, precision, and a recommended action.","tips":["Lead with the risk and its size.","Precise on the trigger and the window.","End with your recommended action, owned, not just the alarm."],"focus":["structure","impact"],"placeholder":"I'm flagging a possible $500K shortfall: if both enterprise renewals slip past year-end, which now looks more likely than not, we miss plan by that much. My recommendation is to hold the contingency and pull forward the cost-review we'd planned for Q4."},
    {"id":"together-fin-mid-18","level":"mid","profession":"finance","title":"The declined request, reader-edited","scenario":"You've drafted a decline of a $30K request but it's four soft paragraphs. Edit it as the requester would read it — looking for the answer — into something clear, kind, and complete.","task":"Write the edited 3-sentence decline: verdict, reason, path, nothing wasted.","tips":["Edit for the reader hunting the answer — put it first.","One reason, one path forward.","Kind is clear; cut everything that delays the verdict."],"focus":["concision","clarity"]},
    {"id":"together-fin-mid-19","level":"mid","profession":"finance","title":"The persuasive capex case, integrated","scenario":"You're making the case for a $380K investment to the approval committee: it needs a before/after narrative, precise payback, a pre-empted objection, and a clear recommendation — the whole toolkit in one page.","task":"Write the 4-5 sentence core of the case integrating narrative, precision, and a pre-empted objection.","tips":["Open on the problem the investment solves, concretely.","Weave in the precise payback as proof.","Pre-empt the committee's hardest question, then recommend."],"focus":["impact","structure"]},
    {"id":"together-fin-mid-20","level":"mid","profession":"finance","title":"The forecast Q&A, composed","scenario":"After presenting the forecast, you face a barrage: 'why should we trust it,' 'what's the downside,' 'what if the big deal slips.' You need to answer each actually-asked question, first, with specifics, staying composed.","task":"Write composed 2-sentence answers to two of the three questions, each answering what was asked first.","tips":["Answer the exact question before adding context.","Specifics over defensiveness, every time.","Stay even; composure is half the credibility."],"focus":["impact","precision"]},
    {"id":"together-fin-mid-21","level":"mid","profession":"finance","title":"The weekly CFO's-office update, refined","scenario":"Your weekly update to the CFO's office tends to sprawl. This week: on track, one decision needed, two FYIs. It should separate decisions from information, lead with what matters, and fit in a phone-screen glance.","task":"Write the refined update with a decisions section and an FYI section, tight and scannable.","tips":["Decisions first, labeled; FYIs second, labeled.","Each item one line, scannable on a phone.","Lead the whole thing with the one-line bottom line."],"focus":["structure","concision"],"placeholder":"Bottom line: on track for the year. Decision needed by Friday: release or hold the $250K contingency (I recommend hold). FYI:"},
    {"id":"together-fin-mid-22","level":"mid","profession":"finance","title":"The hard conversation, planned and delivered","scenario":"You need to tell a peer department head, face to face, that their overspending is now an audit risk and must stop. Plan the spoken open: front-load the message, be specific, stay respectful, keep the partnership.","task":"Write the 3-4 sentence spoken open for the conversation, integrating hard-message delivery and composure.","tips":["Front-load the message — don't circle it for five minutes.","Specific behavior and specific consequence.","Respectful and partnership-preserving, but not vague."],"focus":["clarity","impact"]},
    {"id":"together-fin-mid-23","level":"mid","profession":"finance","title":"The number explained to two audiences at once","scenario":"You must write one short note about a $200K variance that both the CFO's office (wants the year impact) and the department head (wants to know if they're in trouble) will read. You choose to write two tight versions.","task":"Write both: the 2-sentence CFO's-office version and the 2-sentence department-head version.","tips":["One note per audience beats one note for both.","CFO version: year impact and action.","Department version: are you in trouble, and what to do."],"focus":["audience","concision"]},
    {"id":"together-fin-mid-24","level":"mid","profession":"finance","title":"The recommendation the CFO will act on","scenario":"You're recommending the CFO's office approve a spending freeze on discretionary travel to protect the year. It must lead with the recommendation, quantify the benefit, pre-empt the objection, and read as decisive.","task":"Write the 3-4 sentence recommendation integrating BLUF, precision, presence, and a pre-empted objection.","tips":["Recommendation first, in plain words.","Quantify what it saves and protects.","Pre-empt the 'this hurts morale' objection with the trade-off."],"focus":["impact","precision"],"placeholder":"I recommend freezing discretionary travel for the rest of the year, saving about $250K and closing most of the forecast gap. I know it's unpopular, but it protects the alternative — cutting headcount — and it's fully reversible once the two renewals close."},
    {"id":"together-fin-mid-25","level":"mid","profession":"finance","title":"The full year-end wrap to leadership","scenario":"You're delivering the year-end finance summary to the leadership team: how the year landed, what drove it, what it means for next year. Two minutes, spoken, everything you've practiced — structure, precision, presence, narrative — in one.","task":"Write the 2-minute spoken summary: the verdict, two drivers, the forward implication, owned and structured.","tips":["Verdict first — how the year landed, in one number.","Two drivers, quantified, no more.","End on what it means for next year, owned as your view — and make it land aloud."],"focus":["structure","impact"],"placeholder":"The year landed 2% ahead of plan on the bottom line, despite revenue coming in slightly light. Two things drove it: disciplined cost control across departments, worth about $1.5M, and the collections improvement that freed cash all year. For next year, my read is"}
  ],
};
